// Timelines by country — updated July 2026
window.TIMELINES = {"gb":{"name":"the United Kingdom","strap":"From conquest and parliamentary government to devolution, Brexit and Labour’s return.","flag":"<svg xmlns=\"http://www.w3.org/2000/svg\" id=\"flag-icons-gb\" viewBox=\"0 0 640 480\"> <path fill=\"#012169\" d=\"M0 0h640v480H0z\"/> <path fill=\"#FFF\" d=\"m75 0 244 181L562 0h78v62L400 241l240 178v61h-80L320 301 81 480H0v-60l239-178L0 64V0z\"/> <path fill=\"#C8102E\" d=\"m424 281 216 159v40L369 281zm-184 20 6 35L54 480H0zM640 0v3L391 191l2-44L590 0zM0 0l239 176h-60L0 42z\"/> <path fill=\"#FFF\" d=\"M241 0v480h160V0zM0 160v160h640V160z\"/> <path fill=\"#C8102E\" d=\"M0 193v96h640v-96zM273 0v480h96V0z\"/> </svg>","events":[{"year":1066,"date":"1066","era":"state","tag":"Building the state","title":"The Norman Conquest","summary":"William the Conqueror defeats Harold at Hastings.","what":"Norman rule transformed landholding, government, the aristocracy and the English language.","why":"The conquest linked England more closely to continental Europe and helped create a more centralised monarchy.","keywords":["Norman Conquest","Hastings","centralisation"],"colle":"How far can a conquest reshape a national identity?"},{"year":1215,"date":"1215","era":"state","tag":"Building the state","title":"Magna Carta","summary":"The king’s power is formally limited.","what":"King John accepted a charter limiting royal authority and recognising that the monarch was not above the law.","why":"It became a founding myth of English liberties, constitutional restraint and the rule of law.","keywords":["limited government","the rule of law","individual liberties"],"colle":"Can a symbolic historical text still shape modern democracy?"},{"year":1534,"date":"1534","era":"state","tag":"Building the state","title":"The Anglican Reformation","summary":"Henry VIII breaks with Rome.","what":"The Act of Supremacy made the monarch head of the Church of England.","why":"The monarch remains Supreme Governor of the established Church of England, linking religion and the constitution.","keywords":["Church of England","established church","religious settlement"],"colle":"Is an established church compatible with a modern, secular society?"},{"year":1688,"date":"1688–89","era":"state","tag":"Building the state","title":"Glorious Revolution & Bill of Rights","summary":"Parliamentary supremacy is consolidated.","what":"James II was removed and William and Mary accepted statutory limits on royal power.","why":"The settlement established the basis of constitutional monarchy and parliamentary sovereignty.","keywords":["constitutional monarchy","parliamentary sovereignty","Bill of Rights"],"colle":"Does Britain need a written constitution?"},{"year":1707,"date":"1707","era":"state","tag":"Building the state","title":"Act of Union","summary":"England and Scotland form Great Britain.","what":"The English and Scottish Parliaments were united at Westminster.","why":"The survival of the Union is now questioned by Scottish nationalism and the consequences of Brexit.","keywords":["the Union","Scottish identity","Westminster"],"colle":"Is the United Kingdom still genuinely united?"},{"year":1801,"date":"1801","era":"state","tag":"Building the state","title":"Union with Ireland","summary":"The United Kingdom of Great Britain and Ireland is created.","what":"Ireland was formally incorporated into the United Kingdom.","why":"The later partition of Ireland and Northern Ireland’s status remain central constitutional questions.","keywords":["unionism","Irish nationalism","partition"],"colle":"Could Irish reunification reshape the UK?"},{"year":1807,"date":"1807","era":"empire","tag":"Empire & industry","title":"Abolition of the slave trade","summary":"Britain bans the transatlantic slave trade.","what":"British ships were prohibited from transporting enslaved people, although slavery itself continued in the Empire.","why":"The date is central to debates over national pride, responsibility and the memory of slavery.","keywords":["abolition","slave trade","historical memory"],"colle":"How should Britain remember both its role in slavery and in abolition?"},{"year":1832,"date":"1832","era":"empire","tag":"Empire & industry","title":"The Great Reform Act","summary":"Parliament becomes more representative, but democracy remains limited.","what":"The Act redistributed seats and expanded the male electorate while excluding most working-class men and all women.","why":"It began a long sequence of electoral reforms that gradually produced mass democracy.","keywords":["electoral reform","representation","franchise"],"colle":"Is gradual reform more stable than constitutional rupture?"},{"year":1833,"date":"1833","era":"empire","tag":"Empire & industry","title":"Abolition of slavery in the Empire","summary":"Slavery is abolished across most of the British Empire.","what":"The Slavery Abolition Act emancipated enslaved people in most British colonies.","why":"Compensation went mainly to slave owners, a fact now central to debates about reparations.","keywords":["emancipation","reparations","colonial legacy"],"colle":"Should former colonial powers pay reparations?"},{"year":1837,"date":"1837–1901","era":"empire","tag":"Empire & industry","title":"The Victorian era","summary":"Industrial power and imperial expansion reach their height.","what":"Britain became the “workshop of the world” and ruled a vast empire under Queen Victoria.","why":"The era shaped Britain’s global influence, class structure, cities and imperial memory.","keywords":["Industrial Revolution","British Empire","urbanisation"],"colle":"Is imperial nostalgia preventing Britain from facing its past?"},{"year":1914,"date":"1914–18","era":"war","tag":"World wars & democracy","title":"The First World War","summary":"A generation is marked by mass warfare and loss.","what":"Britain fought with the Allies in a conflict that caused enormous military and civilian sacrifice.","why":"Remembrance culture and the poppy remain major elements of British public life.","keywords":["remembrance","the trenches","the poppy"],"colle":"How do national rituals shape collective memory?"},{"year":1918,"date":"1918","era":"war","tag":"World wars & democracy","title":"Representation of the People Act","summary":"Most adult men and some women receive the vote.","what":"The Act enfranchised men over 21 and women over 30 who met property qualifications; equal voting rights followed in 1928.","why":"It transformed Britain into a mass electoral democracy and accelerated women’s political participation.","keywords":["women’s suffrage","mass democracy","franchise"],"colle":"Why did war accelerate democratic reform?"},{"year":1922,"date":"1922","era":"war","tag":"World wars & democracy","title":"The Irish Free State is established","summary":"Most of Ireland leaves the United Kingdom.","what":"The Anglo-Irish settlement created the Irish Free State while Northern Ireland remained in the UK.","why":"The settlement defined the modern territorial shape of the United Kingdom and left the border question unresolved.","keywords":["Irish independence","Northern Ireland","partition"],"colle":"Can political partition ever provide a lasting settlement?"},{"year":1939,"date":"1939–45","era":"war","tag":"World wars & democracy","title":"The Second World War","summary":"Churchill, the Blitz and Britain’s “finest hour”.","what":"Britain resisted Nazi Germany, endured the Blitz and emerged victorious but exhausted and indebted.","why":"The war remains one of the strongest sources of British national mythology.","keywords":["the Blitz","Winston Churchill","national resilience"],"colle":"Can heroic national myths distort present-day political choices?"},{"year":1942,"date":"1942","era":"welfare","tag":"Welfare & decolonisation","title":"The Beveridge Report","summary":"A blueprint for the post-war welfare state.","what":"William Beveridge proposed tackling want, disease, ignorance, squalor and idleness.","why":"The report laid the intellectual foundations of the modern British welfare state.","keywords":["welfare state","social solidarity","public services"],"colle":"How much responsibility should the state assume for citizens’ welfare?"},{"year":1945,"date":"1945","era":"welfare","tag":"Welfare & decolonisation","title":"Labour’s post-war landslide","summary":"Clement Attlee’s government builds the welfare state.","what":"Labour nationalised key industries, expanded social security and began major public-housing programmes.","why":"The settlement shaped British politics for decades and made universal public services part of national identity.","keywords":["Attlee","nationalisation","post-war consensus"],"colle":"Does the post-war settlement still define what Britons expect from government?"},{"year":1948,"date":"1948","era":"welfare","tag":"Welfare & decolonisation","title":"Creation of the NHS","summary":"Universal healthcare becomes a national institution.","what":"The National Health Service began providing healthcare free at the point of use and funded through taxation.","why":"The NHS is both a symbol of social solidarity and a service under severe pressure.","keywords":["universal healthcare","taxation","waiting lists"],"colle":"Can the NHS be reformed without betraying its founding promise?"},{"year":1948.1,"date":"1948","era":"welfare","tag":"Welfare & decolonisation","title":"The Empire Windrush arrives","summary":"A landmark in post-war immigration.","what":"Caribbean migrants arrived to help rebuild Britain after the war.","why":"Windrush symbolises multicultural Britain and the continuing legacy of Empire.","keywords":["Windrush generation","multiculturalism","post-colonial migration"],"colle":"Is immigration a challenge to British identity, or one of its foundations?"},{"year":1956,"date":"1956","era":"welfare","tag":"Welfare & decolonisation","title":"The Suez Crisis","summary":"A symbol of Britain’s declining global power.","what":"Britain, France and Israel intervened in Egypt but withdrew under international pressure.","why":"Suez exposed Britain’s dependence on the United States and the end of superpower status.","keywords":["decline","special relationship","post-imperial power"],"colle":"What remains of British global power today?"},{"year":1965,"date":"1965","era":"welfare","tag":"Welfare & decolonisation","title":"The first Race Relations Act","summary":"Parliament begins outlawing racial discrimination.","what":"The Act prohibited discrimination in public places and created a Race Relations Board, though its scope was limited.","why":"It was an early legal response to racism in a country transformed by post-war migration.","keywords":["anti-discrimination law","racism","multicultural Britain"],"colle":"Can legislation change social attitudes as well as behaviour?"},{"year":1973,"date":"1973","era":"modern","tag":"Modern Britain","title":"The UK joins the EEC","summary":"Britain enters the European project.","what":"The UK joined the European Economic Community after years of debate and failed applications.","why":"Membership began a difficult relationship with Europe that culminated in Brexit.","keywords":["European integration","Euroscepticism","sovereignty"],"colle":"Why has Britain’s relationship with Europe always been so uneasy?"},{"year":1979,"date":"1979","era":"modern","tag":"Modern Britain","title":"Margaret Thatcher becomes Prime Minister","summary":"The neoliberal turn begins.","what":"Thatcher launched privatisation, deregulation, tax cuts and confrontation with trade unions.","why":"Thatcherism permanently reshaped the economy and Britain’s political vocabulary.","keywords":["privatisation","deregulation","trade unions"],"colle":"Did Thatcher modernise Britain or deepen its inequalities?"},{"year":1982,"date":"1982","era":"modern","tag":"Modern Britain","title":"The Falklands War","summary":"Military victory revives patriotic confidence.","what":"Britain retook the Falkland Islands after Argentina’s invasion.","why":"The war strengthened Thatcher politically and remains central to debates over sovereignty and post-imperial power.","keywords":["Falklands","sovereignty","patriotism"],"colle":"Can military success transform domestic politics?"},{"year":1984,"date":"1984–85","era":"modern","tag":"Modern Britain","title":"The miners’ strike","summary":"A decisive defeat for organised labour.","what":"Coal miners fought pit closures in a bitter year-long confrontation with Thatcher’s government.","why":"The defeat accelerated deindustrialisation and weakened trade union power.","keywords":["industrial action","deindustrialisation","working class"],"colle":"How does economic change reshape communities and political loyalties?"},{"year":1997,"date":"1997","era":"modern","tag":"Modern Britain","title":"New Labour comes to power","summary":"Tony Blair promises a “Third Way”.","what":"Labour returned after eighteen years, combining market economics with social investment.","why":"New Labour reshaped the centre-left, but the Iraq War later damaged its legacy.","keywords":["Third Way","modernisation","Tony Blair"],"colle":"Can centre-left parties combine market efficiency with social justice?"},{"year":1998,"date":"1998","era":"modern","tag":"Modern Britain","title":"The Good Friday Agreement","summary":"A peace settlement for Northern Ireland.","what":"The agreement created power-sharing institutions and largely ended the Troubles.","why":"Brexit complicated the border question and tested the settlement’s stability.","keywords":["power-sharing","the Troubles","Irish border"],"colle":"Can peace survive when constitutional identities remain unresolved?"},{"year":1999,"date":"1999","era":"modern","tag":"Modern Britain","title":"Devolution takes effect","summary":"New institutions open in Scotland, Wales and Northern Ireland.","what":"Holyrood, the Welsh Assembly and Stormont received powers from Westminster.","why":"Devolution granted autonomy but also strengthened national identities and independence movements.","keywords":["Holyrood","the Senedd","Stormont"],"colle":"Has devolution saved the Union or weakened it?"},{"year":2003,"date":"2003","era":"modern","tag":"Modern Britain","title":"The Iraq War","summary":"Britain joins the US-led invasion of Iraq.","what":"Tony Blair’s government supported military intervention despite major public protests and disputed intelligence.","why":"The war damaged trust in government and continues to shape arguments about Britain’s alliance with the United States.","keywords":["Iraq War","special relationship","public trust"],"colle":"When should Britain support US military intervention?"},{"year":2008,"date":"2008","era":"modern","tag":"Modern Britain","title":"The global financial crisis","summary":"Bank failures trigger recession and state intervention.","what":"The government rescued major banks as unemployment and public debt rose.","why":"The crisis led to years of austerity and intensified regional and generational inequality.","keywords":["bank bailout","austerity","inequality"],"colle":"Did austerity solve the crisis or deepen its social consequences?"},{"year":2009,"date":"2009","era":"modern","tag":"Modern Britain","title":"The Supreme Court is created","summary":"The highest court becomes institutionally separate from Parliament.","what":"The new Supreme Court replaced the judicial role of the Law Lords.","why":"It strengthened the visible separation of powers and later played a major role during Brexit.","keywords":["Supreme Court","judicial independence","separation of powers"],"colle":"Should judges be able to restrain elected governments?"},{"year":2014,"date":"2014","era":"modern","tag":"Modern Britain","title":"Scottish independence referendum","summary":"Scotland votes 55% to remain in the UK.","what":"Scottish voters rejected independence, but the issue remained politically alive.","why":"Scotland’s later Remain vote in the Brexit referendum revived demands for another vote.","keywords":["self-determination","Scottish nationalism","the Union"],"colle":"Should Scotland be allowed to hold another referendum?"},{"year":2016,"date":"2016","era":"modern","tag":"Modern Britain","title":"The Brexit referendum","summary":"51.9% vote to leave the European Union.","what":"Leave won after a campaign centred on sovereignty, immigration and “taking back control”.","why":"The referendum exposed deep territorial, social and generational divisions.","keywords":["sovereignty","Euroscepticism","political fragmentation"],"colle":"Was Brexit primarily a vote about Europe or about British identity?"},{"year":2020,"date":"2020","era":"modern","tag":"Modern Britain","title":"The UK leaves the European Union","summary":"Brexit becomes legally effective.","what":"The UK formally left the EU on 31 January 2020, with the transition ending later that year.","why":"The consequences for trade, immigration, Northern Ireland and Britain’s world role remain major debates.","keywords":["trade barriers","Global Britain","regulatory divergence"],"colle":"Has Brexit delivered the control and opportunities promised?"},{"year":2022,"date":"2022","era":"modern","tag":"Modern Britain","title":"Elizabeth II dies; Charles III succeeds","summary":"A historic royal transition.","what":"Queen Elizabeth II died after a seventy-year reign and Charles III became King.","why":"The transition reopened debates about monarchy, continuity, cost and relevance.","keywords":["succession","constitutional monarchy","republicanism"],"colle":"Can the monarchy remain relevant to younger generations?"},{"year":2024,"date":"2024","era":"modern","tag":"Modern Britain","title":"Labour returns to power","summary":"Keir Starmer becomes Prime Minister.","what":"Labour won the general election after fourteen years of Conservative-led government.","why":"The change marked a political reset amid pressure on public services, living standards and trust.","keywords":["general election","public services","political change"],"colle":"Can a change of government restore trust in British politics?"}],"priority":["1066 — the Norman Conquest","1215 — Magna Carta","1689 — the Bill of Rights","1707 — the Act of Union","1918 — mass suffrage","1945–48 — the welfare state and NHS","1979 — Thatcher","1998 — the Good Friday Agreement and devolution","2016 — the Brexit referendum","2020 — leaving the EU","2024 — Labour returns"]},"us":{"name":"the United States","strap":"From colonisation and revolution to civil rights, global power and a second Trump presidency.","flag":"<svg xmlns=\"http://www.w3.org/2000/svg\" id=\"flag-icons-us\" viewBox=\"0 0 640 480\"> <path fill=\"#bd3d44\" d=\"M0 0h640v480H0\"/> <path stroke=\"#fff\" stroke-width=\"37\" d=\"M0 55.3h640M0 129h640M0 203h640M0 277h640M0 351h640M0 425h640\"/> <path fill=\"#192f5d\" d=\"M0 0h364.8v258.5H0\"/> <marker id=\"us-a\" markerHeight=\"30\" markerWidth=\"30\"> <path fill=\"#fff\" d=\"m14 0 9 27L0 10h28L5 27z\"/> </marker> <path fill=\"none\" marker-mid=\"url(#us-a)\" d=\"m0 0 16 11h61 61 61 61 60L47 37h61 61 60 61L16 63h61 61 61 61 60L47 89h61 61 60 61L16 115h61 61 61 61 60L47 141h61 61 60 61L16 166h61 61 61 61 60L47 192h61 61 60 61L16 218h61 61 61 61 60z\"/> </svg>","events":[{"year":1607,"date":"1607","era":"origins","tag":"Colonies & foundations","title":"Jamestown is founded","summary":"The first permanent English settlement takes root in Virginia.","what":"The Virginia Company established Jamestown as a commercial colony.","why":"It began the expansion of English settlement and the dispossession of Indigenous peoples along the Atlantic coast.","keywords":["Jamestown","settler colonialism","Virginia"],"colle":"Can a nation celebrate its origins without hiding colonial violence?"},{"year":1619,"date":"1619","era":"origins","tag":"Colonies & foundations","title":"Representative government and forced labour in Virginia","summary":"Two foundations of colonial America emerge in the same year.","what":"Virginia’s first representative assembly met, while the first recorded Africans in English Virginia arrived under coercive conditions.","why":"The date captures the contradiction between self-government for some and racial exploitation for others.","keywords":["House of Burgesses","racial slavery","Virginia"],"colle":"Was inequality built into American democracy from the beginning?"},{"year":1776,"date":"1776","era":"origins","tag":"Colonies & foundations","title":"Declaration of Independence","summary":"The colonies proclaim a universal language of rights.","what":"The Declaration announced separation from Britain and asserted that all people possess unalienable rights.","why":"Its promise of equality remains the yardstick for debates about citizenship, race and justice.","keywords":["independence","natural rights","equality"],"colle":"Has America lived up to its founding promise of equality?"},{"year":1787,"date":"1787","era":"origins","tag":"Colonies & foundations","title":"The Constitution","summary":"Federalism and checks and balances become the political framework.","what":"Delegates created a stronger federal government divided among executive, legislative and judicial branches.","why":"Nearly every modern institutional dispute turns on how this eighteenth-century document should be interpreted.","keywords":["federalism","checks and balances","separation of powers"],"colle":"Are checks and balances still working?"},{"year":1791,"date":"1791","era":"origins","tag":"Colonies & foundations","title":"The Bill of Rights","summary":"Civil liberties are added to the Constitution.","what":"The first ten amendments protected freedoms such as speech, religion, due process and the right to bear arms.","why":"Their interpretation remains central to arguments about individual liberty and public safety.","keywords":["First Amendment","Second Amendment","civil liberties"],"colle":"Are constitutional rights too difficult to adapt to modern society?"},{"year":1803,"date":"1803","era":"expansion","tag":"Expansion & conflict","title":"The Louisiana Purchase","summary":"The country doubles in size.","what":"The United States bought a vast territory from France and accelerated westward expansion.","why":"Expansion strengthened the republic but intensified Indigenous dispossession and conflict over the spread of slavery.","keywords":["westward expansion","Manifest Destiny","Indigenous dispossession"],"colle":"Can territorial expansion ever be separated from violence?"},{"year":1830,"date":"1830s","era":"expansion","tag":"Expansion & conflict","title":"Indian Removal","summary":"Federal policy forces Indigenous nations westward.","what":"The Indian Removal Act enabled the expulsion of Native peoples from their homelands, culminating in the Trail of Tears.","why":"It exposes the gap between democratic ideals and settler colonialism.","keywords":["Trail of Tears","Native Americans","forced removal"],"colle":"How should the United States address the legacy of Indigenous dispossession?"},{"year":1861,"date":"1861–65","era":"expansion","tag":"Expansion & conflict","title":"The Civil War","summary":"The Union survives a war fought over slavery and federal power.","what":"Eleven slaveholding states seceded; Union victory preserved the country and destroyed legal slavery.","why":"The conflict remains central to disputes over race, states’ rights and national memory.","keywords":["Civil War","Union","Confederacy"],"colle":"Why does the Civil War remain politically alive?"},{"year":1865,"date":"1865","era":"expansion","tag":"Expansion & conflict","title":"The Thirteenth Amendment","summary":"Slavery is abolished nationwide.","what":"The amendment prohibited slavery and involuntary servitude, except as punishment for crime.","why":"Abolition ended legal bondage but did not end racial domination or economic exploitation.","keywords":["abolition","Thirteenth Amendment","racial justice"],"colle":"Did emancipation create genuine freedom?"},{"year":1868,"date":"1868","era":"expansion","tag":"Expansion & conflict","title":"The Fourteenth Amendment","summary":"Citizenship and equal protection enter the Constitution.","what":"The amendment defined national citizenship and required states to provide due process and equal protection.","why":"It became the constitutional foundation for civil-rights litigation, including school desegregation and marriage equality.","keywords":["equal protection","citizenship","due process"],"colle":"Should courts use the Fourteenth Amendment to expand rights?"},{"year":1890,"date":"c. 1890–1920","era":"industrial","tag":"Industrial America","title":"Industrialisation and mass immigration","summary":"The United States becomes an urban industrial power.","what":"Factories, railways and corporations expanded while millions of immigrants arrived and labour conflict intensified.","why":"The period created enormous wealth but also inequality, segregation and pressure for progressive reform.","keywords":["industrialisation","immigration","Gilded Age"],"colle":"Does economic dynamism inevitably produce inequality?"},{"year":1929,"date":"1929","era":"crisis","tag":"Crisis & global power","title":"The Wall Street Crash","summary":"Financial collapse begins the Great Depression.","what":"Bank failures, unemployment and falling production devastated households and businesses.","why":"The crisis discredited laissez-faire assumptions and expanded expectations of federal responsibility.","keywords":["Great Depression","unemployment","financial regulation"],"colle":"How much should government intervene during an economic crisis?"},{"year":1933,"date":"1933–39","era":"crisis","tag":"Crisis & global power","title":"The New Deal","summary":"Franklin D. Roosevelt expands the federal state.","what":"Public works, social insurance, labour protections and financial regulation sought relief, recovery and reform.","why":"The New Deal created a lasting debate over whether federal power protects freedom or threatens it.","keywords":["New Deal","Social Security","federal government"],"colle":"Did the New Deal save capitalism by reforming it?"},{"year":1941,"date":"1941","era":"crisis","tag":"Crisis & global power","title":"Pearl Harbor and entry into WWII","summary":"The United States enters the Second World War.","what":"Japan’s attack on Pearl Harbor brought the country into a global conflict.","why":"Wartime mobilisation ended the Depression, expanded federal power and accelerated America’s rise to superpower status.","keywords":["Pearl Harbor","wartime mobilisation","superpower"],"colle":"How did war transform the role of the United States?"},{"year":1945,"date":"1945","era":"crisis","tag":"Crisis & global power","title":"The atomic bomb and the post-war order","summary":"The United States emerges as a global superpower.","what":"Atomic bombs were dropped on Hiroshima and Nagasaki, and the US helped design institutions such as the United Nations.","why":"The moment began the nuclear age and a permanent American leadership role in world affairs.","keywords":["nuclear weapons","United Nations","global leadership"],"colle":"Can the use of atomic weapons ever be justified?"},{"year":1954,"date":"1954","era":"rights","tag":"Civil rights & social change","title":"Brown v. Board of Education","summary":"The Supreme Court rejects segregated public schools.","what":"The Court ruled that separate educational facilities are inherently unequal.","why":"The decision gave constitutional force to the Civil Rights Movement, though implementation met fierce resistance.","keywords":["school desegregation","Supreme Court","equal protection"],"colle":"Can court decisions change society without political enforcement?"},{"year":1963,"date":"1963","era":"rights","tag":"Civil rights & social change","title":"The March on Washington","summary":"Martin Luther King Jr delivers “I Have a Dream”.","what":"A huge interracial demonstration demanded civil and economic rights.","why":"The speech became a moral reference point, but its radical demands for economic justice are often softened in public memory.","keywords":["Martin Luther King Jr","March on Washington","racial equality"],"colle":"Has the dream of racial equality been achieved?"},{"year":1964,"date":"1964","era":"rights","tag":"Civil rights & social change","title":"The Civil Rights Act","summary":"Federal law attacks segregation and discrimination.","what":"The Act prohibited discrimination in public accommodations and employment on grounds including race, colour, religion, sex and national origin.","why":"It marked a decisive federal intervention against Jim Crow.","keywords":["Civil Rights Act","desegregation","employment discrimination"],"colle":"Is anti-discrimination law enough to produce equality?"},{"year":1965,"date":"1965","era":"rights","tag":"Civil rights & social change","title":"The Voting Rights Act","summary":"Federal power protects access to the ballot.","what":"The Act targeted racial barriers such as literacy tests and authorised federal oversight in jurisdictions with histories of discrimination.","why":"Later court decisions and state laws revived debate over how voting rights should be protected.","keywords":["voting rights","Jim Crow","voter suppression"],"colle":"Is voting access equally protected across the United States?"},{"year":1969,"date":"1969","era":"rights","tag":"Civil rights & social change","title":"The Moon landing","summary":"Apollo 11 places humans on the Moon.","what":"Neil Armstrong and Buzz Aldrin walked on the lunar surface during the Cold War space race.","why":"The achievement symbolised technological ambition, federal investment and American soft power.","keywords":["Apollo 11","space race","innovation"],"colle":"Can large public projects still unite a divided nation?"},{"year":1974,"date":"1974","era":"rights","tag":"Civil rights & social change","title":"Watergate and Nixon’s resignation","summary":"A president resigns after abuse of power.","what":"Investigations into the Watergate break-in exposed obstruction and misuse of executive authority.","why":"The scandal strengthened oversight but also deepened long-term distrust of institutions.","keywords":["Watergate","executive power","accountability"],"colle":"Can democratic institutions effectively restrain a president?"},{"year":1980,"date":"1980","era":"contemporary","tag":"Contemporary America","title":"The Reagan revolution","summary":"Conservatism reshapes national politics.","what":"Ronald Reagan promoted tax cuts, deregulation, military strength and a smaller domestic role for government.","why":"Reaganism shifted political debate to the right and still shapes arguments about taxes, welfare and national identity.","keywords":["Reaganomics","conservatism","deregulation"],"colle":"Did Reagan restore confidence or increase inequality?"},{"year":2001,"date":"2001","era":"contemporary","tag":"Contemporary America","title":"The 9/11 attacks","summary":"Terrorist attacks reshape security and foreign policy.","what":"Al-Qaeda attacks killed nearly 3,000 people and prompted wars in Afghanistan and Iraq.","why":"The “war on terror” expanded surveillance and executive power while raising enduring questions about civil liberties.","keywords":["9/11","war on terror","Homeland Security"],"colle":"Did the response to 9/11 sacrifice too much liberty for security?"},{"year":2008,"date":"2008","era":"contemporary","tag":"Contemporary America","title":"Financial crisis and Obama’s election","summary":"Economic collapse coincides with a historic election.","what":"A severe financial crisis triggered bailouts and recession, while Barack Obama became the first Black president.","why":"The year symbolised both racial progress and anger at economic inequality and political elites.","keywords":["Barack Obama","financial crisis","racial progress"],"colle":"Did Obama’s election mark a post-racial turning point?"},{"year":2010,"date":"2010","era":"contemporary","tag":"Contemporary America","title":"The Affordable Care Act","summary":"The federal government expands health-insurance coverage.","what":"“Obamacare” created marketplaces, subsidies and protections for people with pre-existing conditions.","why":"Healthcare became a defining ideological battle over rights, markets and federal authority.","keywords":["Obamacare","health insurance","federal reform"],"colle":"Should healthcare be treated as a right?"},{"year":2015,"date":"2015","era":"contemporary","tag":"Contemporary America","title":"Obergefell v. Hodges","summary":"Same-sex marriage becomes a constitutional right.","what":"The Supreme Court required all states to license and recognise same-sex marriages.","why":"The ruling marked rapid social change and intensified debate over judicial power and religious liberty.","keywords":["marriage equality","LGBT rights","Supreme Court"],"colle":"Should fundamental rights depend on court rulings?"},{"year":2020,"date":"2020","era":"contemporary","tag":"Contemporary America","title":"Pandemic, George Floyd and mass protest","summary":"A health crisis and racial reckoning collide.","what":"COVID-19 caused mass death and economic disruption, while George Floyd’s murder sparked nationwide Black Lives Matter protests.","why":"The year exposed inequalities in health, policing and political trust.","keywords":["COVID-19","Black Lives Matter","police reform"],"colle":"Why did the pandemic deepen America’s political divisions?"},{"year":2021,"date":"6 January 2021","era":"contemporary","tag":"Contemporary America","title":"The Capitol attack","summary":"A mob attempts to disrupt the certification of the presidential election.","what":"Supporters of Donald Trump stormed the Capitol as Congress counted electoral votes.","why":"The attack made election denial and the peaceful transfer of power central tests of American democracy.","keywords":["January 6","election denial","peaceful transfer of power"],"colle":"How resilient is American democracy when electoral legitimacy is rejected?"},{"year":2022,"date":"2022","era":"contemporary","tag":"Contemporary America","title":"Dobbs overturns Roe v. Wade","summary":"Federal constitutional protection for abortion ends.","what":"The Supreme Court returned abortion regulation to elected governments, producing sharply different state laws.","why":"The decision intensified the culture wars and highlighted the political power of judicial appointments.","keywords":["Dobbs","abortion","states’ rights"],"colle":"Why does abortion remain such a defining political issue?"},{"year":2024,"date":"2024","era":"contemporary","tag":"Contemporary America","title":"Donald Trump wins a second, non-consecutive term","summary":"Voters return Trump to the White House.","what":"Trump defeated Kamala Harris and Republicans also won control of Congress.","why":"The result confirmed the strength of populist nationalism and raised new questions about presidential power, institutions and polarisation.","keywords":["2024 election","Donald Trump","polarisation"],"colle":"What explains the durability of Trumpism?"},{"year":2025,"date":"20 January 2025","era":"contemporary","tag":"Contemporary America","title":"Trump begins his second presidency","summary":"Donald Trump is sworn in as the 47th president.","what":"The administration began with an “America First” programme and extensive use of executive action.","why":"The return of a former president after defeat and impeachment is unprecedented in modern US politics and tests constitutional norms.","keywords":["second Trump presidency","executive orders","America First"],"colle":"Is the modern presidency becoming too powerful?"}],"priority":["1776 — the Declaration of Independence","1787–91 — the Constitution and Bill of Rights","1861–65 — the Civil War and abolition","1933 — the New Deal","1945 — the rise of a superpower","1954–65 — the Civil Rights Movement","1974 — Watergate","2001 — 9/11","2008 — crisis and Obama","2021 — the Capitol attack","2022 — Dobbs","2024–25 — Trump’s return"]},"ie":{"name":"Ireland","strap":"From conquest, famine and revolution to European integration, peace and rapid social change.","flag":"<svg xmlns=\"http://www.w3.org/2000/svg\" id=\"flag-icons-ie\" viewBox=\"0 0 640 480\"> <g fill-rule=\"evenodd\" stroke-width=\"1pt\"> <path fill=\"#fff\" d=\"M0 0h640v480H0z\"/> <path fill=\"#009A49\" d=\"M0 0h213.3v480H0z\"/> <path fill=\"#FF7900\" d=\"M426.7 0H640v480H426.7z\"/> </g> </svg>","events":[{"year":1169,"date":"1169–71","era":"conquest","tag":"Conquest & plantation","title":"The Anglo-Norman invasion","summary":"English political involvement begins.","what":"Anglo-Norman forces arrived and Henry II claimed authority over Ireland.","why":"The intervention began centuries of contested English and later British rule.","keywords":["Anglo-Norman invasion","English rule","colonisation"],"colle":"How far back must we go to understand a modern conflict?"},{"year":1607,"date":"1607","era":"conquest","tag":"Conquest & plantation","title":"The Flight of the Earls","summary":"Gaelic political power collapses in Ulster.","what":"Leading Gaelic lords left Ireland after defeat, opening the way for large-scale plantation.","why":"The settlement of Protestant communities in Ulster shaped later unionism and partition.","keywords":["Ulster Plantation","Gaelic Ireland","settler colonialism"],"colle":"How did plantation shape modern identities in Ireland?"},{"year":1690,"date":"1690","era":"conquest","tag":"Conquest & plantation","title":"The Battle of the Boyne","summary":"Williamite victory confirms Protestant political dominance.","what":"William III defeated James II in a conflict tied to wider European struggles.","why":"The battle remains a powerful symbol in Northern Irish unionist culture.","keywords":["Battle of the Boyne","Williamite victory","unionist memory"],"colle":"Why do historical victories remain politically sensitive?"},{"year":1801,"date":"1801","era":"union","tag":"Union & famine","title":"The Act of Union","summary":"Ireland is incorporated into the United Kingdom.","what":"The Irish Parliament was abolished and representation transferred to Westminster.","why":"The Union created the institutional framework against which modern Irish nationalism developed.","keywords":["Act of Union","Westminster","Irish nationalism"],"colle":"Did the Union make reform easier or independence inevitable?"},{"year":1829,"date":"1829","era":"union","tag":"Union & famine","title":"Catholic Emancipation","summary":"Most legal restrictions on Catholic political participation are removed.","what":"Daniel O’Connell’s mass movement pressured Westminster to allow Catholics to sit in Parliament.","why":"The campaign demonstrated the power of peaceful popular mobilisation.","keywords":["Daniel O’Connell","Catholic Emancipation","mass politics"],"colle":"Can constitutional campaigning achieve revolutionary change?"},{"year":1845,"date":"1845–52","era":"union","tag":"Union & famine","title":"The Great Famine","summary":"Crop failure becomes a demographic catastrophe.","what":"Potato blight caused hunger, disease and mass emigration while British policy responses proved gravely inadequate.","why":"The Famine transformed population, diaspora and attitudes to British rule.","keywords":["Great Famine","emigration","British policy"],"colle":"Was the Famine a natural disaster or a political failure?"},{"year":1916,"date":"1916","era":"revolution","tag":"Revolution & partition","title":"The Easter Rising","summary":"A failed rebellion becomes the symbolic spark of independence.","what":"Republicans seized key buildings in Dublin and proclaimed an Irish Republic before being defeated.","why":"The execution of its leaders shifted public opinion towards separatism.","keywords":["Easter Rising","republicanism","martyrdom"],"colle":"Why can a military defeat become a political victory?"},{"year":1919,"date":"1919–21","era":"revolution","tag":"Revolution & partition","title":"The War of Independence","summary":"Guerrilla conflict challenges British rule.","what":"The IRA fought British forces while the revolutionary Dáil claimed democratic legitimacy.","why":"The conflict forced negotiations but also hardened divisions over sovereignty and violence.","keywords":["War of Independence","IRA","Dáil Éireann"],"colle":"Can political violence be legitimate in an anti-colonial struggle?"},{"year":1921,"date":"1921","era":"revolution","tag":"Revolution & partition","title":"Partition and the Anglo-Irish Treaty","summary":"The island is divided and the Irish Free State is agreed.","what":"The Treaty created a self-governing dominion while six counties remained in Northern Ireland.","why":"Partition produced two states and left competing national identities unresolved.","keywords":["partition","Anglo-Irish Treaty","Northern Ireland"],"colle":"Was partition inevitable?"},{"year":1922,"date":"1922–23","era":"revolution","tag":"Revolution & partition","title":"The Civil War","summary":"Former allies fight over the Treaty.","what":"Pro- and anti-Treaty forces fought over the status and limits of the new state.","why":"The conflict shaped party politics for generations, especially Fianna Fáil and Fine Gael.","keywords":["Civil War","pro-Treaty","anti-Treaty"],"colle":"Why did the Civil War structure Irish politics for so long?"},{"year":1937,"date":"1937","era":"republic","tag":"Republic & modernisation","title":"The Constitution","summary":"A new constitutional order asserts sovereignty.","what":"Bunreacht na hÉireann created the office of President and defined the institutions of the state.","why":"Frequent referendums have allowed the constitution to become a vehicle for social change.","keywords":["Bunreacht na hÉireann","referendum","sovereignty"],"colle":"Does frequent constitutional voting strengthen democracy?"},{"year":1949,"date":"1949","era":"republic","tag":"Republic & modernisation","title":"Ireland becomes a republic","summary":"The state formally leaves the Commonwealth.","what":"The Republic of Ireland Act ended the remaining external role of the British monarch.","why":"The change completed constitutional separation while Northern Ireland remained within the UK.","keywords":["republic","Commonwealth","sovereignty"],"colle":"How important are symbols in completing independence?"},{"year":1973,"date":"1973","era":"europe","tag":"Europe & prosperity","title":"Ireland joins the EEC","summary":"European membership accelerates economic and social change.","what":"Ireland entered the European Economic Community alongside the United Kingdom and Denmark.","why":"Europe provided markets, funding and a counterweight to economic dependence on Britain.","keywords":["European integration","modernisation","structural funds"],"colle":"How did Europe transform Ireland’s place in the world?"},{"year":1985,"date":"1985","era":"europe","tag":"Europe & prosperity","title":"The Anglo-Irish Agreement","summary":"Dublin gains a consultative role in Northern Irish affairs.","what":"The British and Irish governments agreed to closer cooperation despite unionist opposition.","why":"It established habits of intergovernmental partnership that helped prepare the peace process.","keywords":["Anglo-Irish Agreement","Northern Ireland","cooperation"],"colle":"Can outside governments help resolve identity conflicts?"},{"year":1995,"date":"1990s–2007","era":"europe","tag":"Europe & prosperity","title":"The Celtic Tiger","summary":"Rapid growth transforms a once-poor economy.","what":"Foreign investment, EU membership, education and a young workforce drove exceptional expansion.","why":"Prosperity encouraged immigration and social confidence but also created dependence on property and multinational capital.","keywords":["Celtic Tiger","foreign investment","globalisation"],"colle":"Is Ireland’s economic model too dependent on multinational companies?"},{"year":1998,"date":"1998","era":"europe","tag":"Europe & prosperity","title":"The Good Friday Agreement","summary":"A new framework brings peace to Northern Ireland.","what":"The agreement created power-sharing, cross-border institutions and consent-based constitutional rules.","why":"It largely ended the Troubles and made cooperation between London, Dublin and Belfast central to stability.","keywords":["Good Friday Agreement","power-sharing","peace process"],"colle":"Is a united Ireland now more realistic?"},{"year":2008,"date":"2008–10","era":"contemporary","tag":"Contemporary Ireland","title":"The financial crash and bailout","summary":"The Celtic Tiger collapses.","what":"A property and banking crisis forced the state to guarantee banks and accept an EU-IMF assistance programme.","why":"Austerity reshaped politics, housing and public trust.","keywords":["banking crisis","austerity","EU-IMF bailout"],"colle":"Did Ireland recover from the crash at too high a social cost?"},{"year":2015,"date":"2015","era":"contemporary","tag":"Contemporary Ireland","title":"Marriage equality referendum","summary":"Ireland becomes the first country to legalise same-sex marriage by popular vote.","what":"A decisive referendum amended the constitution to permit marriage regardless of sex.","why":"The result symbolised rapid secularisation and generational change.","keywords":["marriage equality","referendum","secularisation"],"colle":"How did Ireland liberalise so quickly?"},{"year":2018,"date":"2018","era":"contemporary","tag":"Contemporary Ireland","title":"Abortion referendum","summary":"Voters repeal the constitutional ban on abortion.","what":"The electorate removed the Eighth Amendment, allowing Parliament to legislate for abortion access.","why":"The vote marked a major shift in women’s rights and the declining authority of the Catholic Church.","keywords":["abortion","women’s rights","Eighth Amendment"],"colle":"Should fundamental rights be decided by referendum?"},{"year":2020,"date":"2020","era":"contemporary","tag":"Contemporary Ireland","title":"Sinn Féin’s electoral breakthrough","summary":"The old two-party system is disrupted.","what":"Sinn Féin won the largest share of first-preference votes, although Fianna Fáil, Fine Gael and the Greens formed a coalition.","why":"Housing, reunification and generational change became central to a more fragmented party system.","keywords":["Sinn Féin","housing crisis","party realignment"],"colle":"Is Ireland moving beyond its Civil War party system?"},{"year":2024,"date":"2024–25","era":"contemporary","tag":"Contemporary Ireland","title":"Election and a new coalition","summary":"Fianna Fáil and Fine Gael remain at the centre of government.","what":"After the November 2024 election, Micheál Martin became Taoiseach in January 2025 with support from Fianna Fáil, Fine Gael and independent deputies.","why":"The outcome showed both continuity and pressure from housing shortages, migration debates and Sinn Féin’s challenge.","keywords":["2024 election","Micheál Martin","coalition government"],"colle":"Can centrist coalition government solve Ireland’s housing crisis?"}],"priority":["1801 — the Act of Union","1845–52 — the Great Famine","1916 — the Easter Rising","1919–21 — the War of Independence","1921 — partition and the Treaty","1922–23 — the Civil War","1937 — the Constitution","1973 — joining the EEC","1998 — the Good Friday Agreement","2008 — the crash","2015–18 — the social referendums","2024–25 — election and coalition"]},"ca":{"name":"Canada","strap":"From Indigenous nations and rival empires to federalism, bilingualism, reconciliation and the Carney era.","flag":"<svg xmlns=\"http://www.w3.org/2000/svg\" id=\"flag-icons-ca\" viewBox=\"0 0 640 480\"> <path fill=\"#fff\" d=\"M150.1 0h339.7v480H150z\"/> <path fill=\"#d52b1e\" d=\"M-19.7 0h169.8v480H-19.7zm509.5 0h169.8v480H489.9zM201 232l-13.3 4.4 61.4 54c4.7 13.7-1.6 17.8-5.6 25l66.6-8.4-1.6 67 13.9-.3-3.1-66.6 66.7 8c-4.1-8.7-7.8-13.3-4-27.2l61.3-51-10.7-4c-8.8-6.8 3.8-32.6 5.6-48.9 0 0-35.7 12.3-38 5.8l-9.2-17.5-32.6 35.8c-3.5.9-5-.5-5.9-3.5l15-74.8-23.8 13.4q-3.2 1.3-5.2-2.2l-23-46-23.6 47.8q-2.8 2.5-5 .7L264 130.8l13.7 74.1c-1.1 3-3.7 3.8-6.7 2.2l-31.2-35.3c-4 6.5-6.8 17.1-12.2 19.5s-23.5-4.5-35.6-7c4.2 14.8 17 39.6 9 47.7\"/> </svg>","events":[{"year":-1000,"date":"Before European colonisation","era":"indigenous","tag":"Indigenous foundations","title":"Diverse Indigenous nations flourish","summary":"First Nations, Inuit and Métis histories predate Canada by millennia.","what":"Complex societies developed distinct political systems, economies, languages and relationships with the land.","why":"Treaty rights, sovereignty and reconciliation cannot be understood if Canadian history begins with Europeans.","keywords":["First Nations","Inuit","Métis"],"colle":"Can a settler state fully recognise Indigenous sovereignty?"},{"year":1608,"date":"1608","era":"colonial","tag":"French & British North America","title":"Quebec City is founded","summary":"New France gains a permanent political centre.","what":"Samuel de Champlain established Quebec as a trading and administrative settlement.","why":"French language, civil law and Catholic culture became enduring foundations of Quebec’s distinct identity.","keywords":["New France","Quebec","French Canada"],"colle":"Is Quebec a nation within Canada?"},{"year":1759,"date":"1759","era":"colonial","tag":"French & British North America","title":"The Battle of the Plains of Abraham","summary":"British victory decides the fate of New France.","what":"British forces defeated the French outside Quebec City during the Seven Years’ War.","why":"The conquest created a bilingual and bicultural political problem that still shapes federalism.","keywords":["British conquest","Plains of Abraham","French Canada"],"colle":"Did conquest create or merely reveal Canada’s dual identity?"},{"year":1763,"date":"1763","era":"colonial","tag":"French & British North America","title":"The Royal Proclamation","summary":"The Crown sets rules for Indigenous land acquisition.","what":"The proclamation recognised that Indigenous lands could be ceded only to the Crown through treaties.","why":"It remains a constitutional reference in Indigenous rights claims, despite repeated violations in practice.","keywords":["Royal Proclamation","treaties","Indigenous land rights"],"colle":"Can historical treaties constrain a modern state?"},{"year":1812,"date":"1812–14","era":"colonial","tag":"French & British North America","title":"The War of 1812","summary":"British North America resists invasion from the United States.","what":"British forces, colonial militias and Indigenous allies defended the colonies during war with the US.","why":"The conflict became a nation-building story, though it often underplays the decisive role and later betrayal of Indigenous allies.","keywords":["War of 1812","United States","Indigenous allies"],"colle":"How are national myths created from ambiguous wars?"},{"year":1867,"date":"1867","era":"nation","tag":"Confederation & nation-building","title":"Confederation","summary":"Canada becomes a federal dominion.","what":"Ontario, Quebec, Nova Scotia and New Brunswick formed a federation under the British North America Act.","why":"Federalism was designed to combine unity with regional and linguistic diversity.","keywords":["Confederation","federalism","Dominion"],"colle":"Does Canadian federalism protect diversity or produce permanent conflict?"},{"year":1885,"date":"1885","era":"nation","tag":"Confederation & nation-building","title":"The railway and the North-West Resistance","summary":"Continental expansion is consolidated through force and infrastructure.","what":"The Canadian Pacific Railway was completed as Métis and First Nations resistance was defeated and Louis Riel executed.","why":"The year links national development to Indigenous dispossession and French-English tensions.","keywords":["Canadian Pacific Railway","Louis Riel","Métis"],"colle":"Can nation-building be separated from colonial violence?"},{"year":1917,"date":"1917","era":"nation","tag":"Confederation & nation-building","title":"Vimy Ridge and the conscription crisis","summary":"War strengthens national identity but divides French and English Canada.","what":"Canadian forces captured Vimy Ridge, while compulsory military service provoked fierce opposition in Quebec.","why":"The contrast shows how the same war can unite a country symbolically and divide it politically.","keywords":["Vimy Ridge","conscription crisis","French-English relations"],"colle":"Do wars create national unity or expose national divisions?"},{"year":1931,"date":"1931","era":"nation","tag":"Confederation & nation-building","title":"The Statute of Westminster","summary":"Canada gains legislative autonomy from Britain.","what":"The statute recognised the equality of self-governing dominions with the United Kingdom.","why":"It marked a major stage in Canada’s gradual, peaceful path to full sovereignty.","keywords":["Statute of Westminster","sovereignty","Commonwealth"],"colle":"Why was Canadian independence so gradual?"},{"year":1947,"date":"1947","era":"identity","tag":"Rights & identity","title":"Canadian citizenship is created","summary":"Canadians receive a distinct legal nationality.","what":"The Canadian Citizenship Act came into force, separating Canadian citizenship from the broader status of British subject.","why":"Citizenship became a tool for defining an independent and increasingly diverse country.","keywords":["Canadian citizenship","national identity","immigration"],"colle":"What should citizenship require beyond legal status?"},{"year":1960,"date":"1960","era":"identity","tag":"Rights & identity","title":"First Nations people gain the federal vote without losing status","summary":"A major formal barrier to political participation is removed.","what":"Status First Nations adults could vote federally without being forced to give up treaty status.","why":"The reform ended one discriminatory rule but did not resolve colonial control under the Indian Act.","keywords":["federal vote","Indian Act","political rights"],"colle":"Can equal voting rights coexist with colonial institutions?"},{"year":1965,"date":"1965","era":"identity","tag":"Rights & identity","title":"The Maple Leaf flag","summary":"Canada adopts a distinctive national symbol.","what":"The new red-and-white flag replaced the Canadian Red Ensign after a divisive parliamentary debate.","why":"The flag signalled a more independent identity less centred on the British Empire.","keywords":["Maple Leaf","flag debate","national identity"],"colle":"Can a new symbol successfully reinvent a country?"},{"year":1969,"date":"1969","era":"identity","tag":"Rights & identity","title":"The Official Languages Act","summary":"English and French receive equal status in federal institutions.","what":"The Act established official bilingualism across the federal government.","why":"It aimed to protect linguistic duality while provoking debate in both Quebec and western Canada.","keywords":["official bilingualism","French language","federal institutions"],"colle":"Is official bilingualism a success?"},{"year":1970,"date":"1970","era":"identity","tag":"Rights & identity","title":"The October Crisis","summary":"Political violence tests civil liberties.","what":"After kidnappings by the FLQ, Pierre Trudeau invoked the War Measures Act and deployed troops.","why":"The crisis remains a key debate about terrorism, emergency powers and Quebec nationalism.","keywords":["October Crisis","FLQ","War Measures Act"],"colle":"When may a democracy suspend civil liberties?"},{"year":1971,"date":"1971","era":"identity","tag":"Rights & identity","title":"Official multiculturalism","summary":"Canada adopts multiculturalism as federal policy.","what":"The government recognised cultural diversity within a bilingual framework.","why":"The “mosaic” became central to Canada’s self-image and immigration model.","keywords":["multiculturalism","mosaic","immigration"],"colle":"Does multiculturalism create inclusion or weaken a shared identity?"},{"year":1982,"date":"1982","era":"identity","tag":"Rights & identity","title":"Patriation and the Charter","summary":"Canada brings its constitution home.","what":"The Constitution Act created a domestic amendment procedure and entrenched the Charter of Rights and Freedoms.","why":"The Charter strengthened judicial review, while Quebec’s government did not consent to the agreement.","keywords":["Charter of Rights","patriation","judicial review"],"colle":"Has the Charter transferred too much power to judges?"},{"year":1995,"date":"1995","era":"identity","tag":"Rights & identity","title":"The Quebec referendum","summary":"Canada comes within one percentage point of breaking apart.","what":"Quebec voters rejected sovereignty by 50.58% to 49.42%.","why":"The razor-thin result forced renewed debate over national unity, recognition and the rules of secession.","keywords":["Quebec sovereignty","referendum","national unity"],"colle":"Could Quebec independence return as a major issue?"},{"year":1999,"date":"1999","era":"contemporary","tag":"Contemporary Canada","title":"Nunavut is created","summary":"A new territory reflects Inuit self-government.","what":"Nunavut was separated from the Northwest Territories following the largest Indigenous land-claim settlement in Canadian history.","why":"It gave Inuit people greater political control while highlighting the continuing challenges of housing, services and Arctic sovereignty.","keywords":["Nunavut","Inuit self-government","Arctic"],"colle":"Can territorial autonomy deliver decolonisation?"},{"year":2008,"date":"2008","era":"contemporary","tag":"Contemporary Canada","title":"Residential-school apology","summary":"The federal government formally apologises to former pupils.","what":"The Prime Minister apologised for a system that removed Indigenous children from families and sought to erase cultures and languages.","why":"The apology opened a national reckoning but did not itself repair intergenerational harm.","keywords":["residential schools","apology","cultural genocide"],"colle":"What makes a state apology meaningful?"},{"year":2015,"date":"2015","era":"contemporary","tag":"Contemporary Canada","title":"Truth and Reconciliation Commission","summary":"The residential-school system is documented as cultural genocide.","what":"The Commission issued 94 Calls to Action after hearing testimony from survivors.","why":"Reconciliation became a central national commitment and a test of whether symbolic recognition produces structural change.","keywords":["Truth and Reconciliation","Calls to Action","Indigenous justice"],"colle":"Why has implementation of reconciliation been so slow?"},{"year":2021,"date":"2021","era":"contemporary","tag":"Contemporary Canada","title":"Unmarked burial sites renew the reckoning","summary":"Ground-penetrating radar findings intensify grief and anger.","what":"Indigenous communities announced evidence of probable unmarked graves near former residential schools.","why":"The discoveries made the violence of assimilation impossible for many Canadians to treat as distant history.","keywords":["unmarked graves","residential schools","historical memory"],"colle":"How should schools and public institutions teach colonial violence?"},{"year":2025,"date":"2025","era":"contemporary","tag":"Contemporary Canada","title":"Mark Carney becomes Prime Minister and wins a minority","summary":"Leadership changes amid tensions with the United States.","what":"Mark Carney was sworn in in March and the Liberals won 169 of 343 seats in the April federal election.","why":"The election centred on sovereignty, economic security and Canada’s relationship with the United States.","keywords":["Mark Carney","2025 election","minority government"],"colle":"Can external pressure strengthen Canadian national unity?"}],"priority":["1608 — Quebec City and New France","1759–63 — conquest and the Royal Proclamation","1867 — Confederation","1885 — the railway and Louis Riel","1931 — legislative independence","1969–71 — bilingualism and multiculturalism","1982 — the Charter","1995 — the Quebec referendum","1999 — Nunavut","2008–15 — residential schools and reconciliation","2025 — the Carney government"]},"au":{"name":"Australia","strap":"From the world’s oldest continuing cultures and settler colonisation to federation, Indigenous recognition debates and Labor’s 2025 victory.","flag":"<svg xmlns=\"http://www.w3.org/2000/svg\" id=\"flag-icons-au\" viewBox=\"0 0 640 480\"> <path fill=\"#00008B\" d=\"M0 0h640v480H0z\"/> <path fill=\"#fff\" d=\"m37.5 0 122 90.5L281 0h39v31l-120 89.5 120 89V240h-40l-120-89.5L40.5 240H0v-30l119.5-89L0 32V0z\"/> <path fill=\"red\" d=\"M212 140.5 320 220v20l-135.5-99.5zm-92 10 3 17.5-96 72H0zM320 0v1.5l-124.5 94 1-22L295 0zM0 0l119.5 88h-30L0 21z\"/> <path fill=\"#fff\" d=\"M120.5 0v240h80V0zM0 80v80h320V80z\"/> <path fill=\"red\" d=\"M0 96.5v48h320v-48zM136.5 0v240h48V0z\"/> <path fill=\"#fff\" d=\"m527 396.7-20.5 2.6 2.2 20.5-14.8-14.4-14.7 14.5 2-20.5-20.5-2.4 17.3-11.2-10.9-17.5 19.6 6.5 6.9-19.5 7.1 19.4 19.5-6.7-10.7 17.6zm-3.7-117.2 2.7-13-9.8-9 13.2-1.5 5.5-12.1 5.5 12.1 13.2 1.5-9.8 9 2.7 13-11.6-6.6zm-104.1-60-20.3 2.2 1.8 20.3-14.4-14.5-14.8 14.1 2.4-20.3-20.2-2.7 17.3-10.8-10.5-17.5 19.3 6.8L387 178l6.7 19.3 19.4-6.3-10.9 17.3 17.1 11.2ZM623 186.7l-20.9 2.7 2.3 20.9-15.1-14.7-15 14.8 2.1-21-20.9-2.4 17.7-11.5-11.1-17.9 20 6.7 7-19.8 7.2 19.8 19.9-6.9-11 18zm-96.1-83.5-20.7 2.3 1.9 20.8-14.7-14.8-15.1 14.4 2.4-20.7-20.7-2.8 17.7-11L467 73.5l19.7 6.9 7.3-19.5 6.8 19.7 19.8-6.5-11.1 17.6zM234 385.7l-45.8 5.4 4.6 45.9-32.8-32.4-33 32.2 4.9-45.9-45.8-5.8 38.9-24.8-24-39.4 43.6 15 15.8-43.4 15.5 43.5 43.7-14.7-24.3 39.2 38.8 25.1Z\"/> </svg>","events":[{"year":-65000,"date":"At least 65,000 years ago","era":"first","tag":"First Peoples","title":"First Peoples establish enduring cultures","summary":"Aboriginal and Torres Strait Islander peoples develop the world’s oldest continuing cultures.","what":"Hundreds of nations created distinct languages, laws, economies and relationships with Country.","why":"Australian history cannot begin in 1788 without reproducing the logic of terra nullius.","keywords":["First Nations","Country","continuous cultures"],"colle":"How should a settler nation rewrite its founding story?"},{"year":1770,"date":"1770","era":"colonial","tag":"Colonisation & expansion","title":"Cook claims the east coast for Britain","summary":"British imperial claims precede settlement.","what":"James Cook mapped the east coast and claimed it for Britain as New South Wales.","why":"The claim ignored existing sovereignty and prepared the way for colonisation.","keywords":["James Cook","British Empire","terra nullius"],"colle":"Can exploration be separated from conquest?"},{"year":1788,"date":"1788","era":"colonial","tag":"Colonisation & expansion","title":"The First Fleet","summary":"A penal colony is established at Sydney Cove.","what":"British convicts, marines and officials arrived and founded New South Wales.","why":"The event is celebrated as national origins by some and remembered as invasion by many Indigenous Australians.","keywords":["First Fleet","convict colony","Invasion Day"],"colle":"Should Australia Day remain on 26 January?"},{"year":1851,"date":"1851","era":"colonial","tag":"Colonisation & expansion","title":"The gold rushes","summary":"Migration and wealth transform the colonies.","what":"Gold discoveries attracted migrants from around the world and accelerated urban growth.","why":"The period promoted social mobility but also racism, environmental damage and conflict over immigration.","keywords":["gold rush","migration","prosperity"],"colle":"Did the gold rush create a more democratic society?"},{"year":1854,"date":"1854","era":"colonial","tag":"Colonisation & expansion","title":"The Eureka Stockade","summary":"Miners rebel against colonial authority.","what":"Gold miners fought troops after demanding fair licences and political representation.","why":"Eureka became a flexible national symbol claimed by democrats, labour activists and nationalists.","keywords":["Eureka Stockade","miners","democracy"],"colle":"Why can one rebellion support very different political myths?"},{"year":1901,"date":"1901","era":"nation","tag":"Federation & nation-building","title":"Federation and White Australia","summary":"The Commonwealth is created alongside racial exclusion.","what":"Six colonies federated, while the Immigration Restriction Act became the foundation of the White Australia policy.","why":"The new democracy combined advanced political institutions with an explicitly racial vision of nationhood.","keywords":["Federation","White Australia","Commonwealth"],"colle":"Was racism built into the Australian nation?"},{"year":1915,"date":"1915","era":"nation","tag":"Federation & nation-building","title":"Gallipoli and ANZAC","summary":"Military defeat becomes a founding national myth.","what":"Australian and New Zealand forces suffered heavy losses in the failed Gallipoli campaign.","why":"ANZAC remembrance celebrates sacrifice and mateship but can overshadow Indigenous history and other wartime experiences.","keywords":["ANZAC","Gallipoli","mateship"],"colle":"Does ANZAC unite Australia or narrow its national story?"},{"year":1942,"date":"1942","era":"nation","tag":"Federation & nation-building","title":"The fall of Singapore and the turn to America","summary":"Britain can no longer guarantee Australia’s security.","what":"Japan captured Singapore and Australia increasingly relied on the United States during the Pacific War.","why":"The strategic pivot reshaped foreign policy while Britain remained culturally important.","keywords":["fall of Singapore","US alliance","Pacific War"],"colle":"Is Australia too dependent on the United States?"},{"year":1962,"date":"1962","era":"rights","tag":"Rights & recognition","title":"Federal voting rights for Indigenous Australians","summary":"Remaining federal exclusions are removed.","what":"Legislation gave all Aboriginal and Torres Strait Islander adults the option to enrol and vote in federal elections.","why":"Formal political inclusion advanced, though enrolment did not become compulsory for Indigenous citizens until later.","keywords":["Indigenous voting rights","franchise","citizenship"],"colle":"Does formal equality guarantee political power?"},{"year":1967,"date":"1967","era":"rights","tag":"Rights & recognition","title":"The 1967 referendum","summary":"A huge majority approves constitutional change concerning Indigenous Australians.","what":"Voters allowed the Commonwealth to make laws for Aboriginal people and removed their exclusion from population counts.","why":"The referendum became a symbol of recognition, although it did not grant citizenship or voting rights.","keywords":["1967 referendum","constitutional recognition","Indigenous rights"],"colle":"Why do national myths sometimes simplify legal change?"},{"year":1973,"date":"1973","era":"rights","tag":"Rights & recognition","title":"The White Australia policy ends","summary":"Immigration policy is formally made non-racial.","what":"The Whitlam government completed the dismantling of discriminatory selection rules and promoted multiculturalism.","why":"The change transformed Australia’s population and its relationship with Asia.","keywords":["multiculturalism","immigration","Asia-Pacific"],"colle":"Has multiculturalism replaced Australia’s racial past?"},{"year":1975,"date":"1975","era":"rights","tag":"Rights & recognition","title":"The Dismissal","summary":"The Governor-General removes the Prime Minister.","what":"John Kerr dismissed Gough Whitlam during a constitutional crisis over supply.","why":"The event demonstrated that the Crown’s reserve powers can still have decisive political effects.","keywords":["the Dismissal","Governor-General","reserve powers"],"colle":"Should Australia replace the monarchy with a republic?"},{"year":1986,"date":"1986","era":"rights","tag":"Rights & recognition","title":"The Australia Act","summary":"Remaining constitutional links with Britain are ended.","what":"Australian and British legislation removed the UK Parliament’s final powers over Australian law and appeals.","why":"It completed legal independence without changing the monarchy.","keywords":["Australia Act","legal independence","monarchy"],"colle":"Can a country be fully independent while sharing a monarch?"},{"year":1992,"date":"1992","era":"rights","tag":"Rights & recognition","title":"The Mabo decision","summary":"The High Court rejects terra nullius.","what":"The Court recognised native title and the Meriam people’s continuing connection to land.","why":"Mabo transformed property law and forced the country to confront the legal fiction behind colonisation.","keywords":["Mabo","native title","terra nullius"],"colle":"Can courts repair historical injustice?"},{"year":1996,"date":"1996","era":"contemporary","tag":"Contemporary Australia","title":"Port Arthur and national gun reform","summary":"Mass murder produces rapid bipartisan legislation.","what":"After 35 people were killed in Tasmania, governments agreed to strict firearms controls and a buyback.","why":"The response is often cited internationally as evidence that political consensus can reduce gun violence.","keywords":["Port Arthur","gun control","National Firearms Agreement"],"colle":"Why was Australia able to adopt gun reform when the US has not?"},{"year":1999,"date":"1999","era":"contemporary","tag":"Contemporary Australia","title":"The republic referendum","summary":"Australians vote to retain the monarchy.","what":"The proposed model for a president appointed by Parliament was rejected by 54.9% of voters.","why":"The result showed that support for a republic does not automatically produce agreement on its form.","keywords":["republic referendum","monarchy","constitutional reform"],"colle":"Could a future republic referendum succeed?"},{"year":2008,"date":"2008","era":"contemporary","tag":"Contemporary Australia","title":"The National Apology","summary":"The Prime Minister apologises to the Stolen Generations.","what":"Kevin Rudd acknowledged policies that removed Indigenous children from families.","why":"The apology was a landmark in recognition, but gaps in health, education, incarceration and life expectancy persisted.","keywords":["Stolen Generations","National Apology","reconciliation"],"colle":"Can symbolic apology matter without material repair?"},{"year":2017,"date":"2017","era":"contemporary","tag":"Contemporary Australia","title":"Marriage equality","summary":"Parliament legalises same-sex marriage after a postal survey.","what":"A national survey returned a clear Yes vote and legislation followed.","why":"The episode showed both rapid social liberalisation and controversy over using a non-binding public vote for minority rights.","keywords":["marriage equality","postal survey","LGBT rights"],"colle":"Should minority rights be put to a popular vote?"},{"year":2023,"date":"2023","era":"contemporary","tag":"Contemporary Australia","title":"The Voice referendum","summary":"Voters reject an Indigenous Voice to Parliament.","what":"The proposed constitutional advisory body failed nationally and in every state.","why":"The result exposed uncertainty, misinformation and deep disagreement over recognition and practical reform.","keywords":["Voice to Parliament","referendum","Indigenous recognition"],"colle":"Why did the Voice referendum fail?"},{"year":2025,"date":"2025","era":"contemporary","tag":"Contemporary Australia","title":"Labor wins a second term with an enlarged majority","summary":"Anthony Albanese is returned decisively.","what":"The Australian Labor Party won 94 of 150 House seats in the federal election.","why":"The result strengthened Labor while cost of living, housing, climate policy and the future of the Coalition remained central debates.","keywords":["2025 election","Anthony Albanese","Labor majority"],"colle":"Does a large parliamentary majority make bold reform more likely?"}],"priority":["At least 65,000 years — First Peoples","1788 — the First Fleet","1851–54 — gold and Eureka","1901 — Federation and White Australia","1915 — ANZAC","1967 — the referendum","1975 — the Dismissal","1992 — Mabo","1996 — gun reform","2008 — the Apology","2023 — the Voice referendum","2025 — Labor’s second term"]},"nz":{"name":"New Zealand","strap":"From Māori settlement and the Treaty of Waitangi to social reform, bicultural revival and today’s Treaty debate.","flag":"<svg xmlns=\"http://www.w3.org/2000/svg\" xmlns:xlink=\"http://www.w3.org/1999/xlink\" id=\"flag-icons-nz\" viewBox=\"0 0 640 480\"> <defs> <g id=\"nz-b\"> <g id=\"nz-a\"> <path d=\"M0-.3v.5l1-.5z\"/> <path d=\"M.2.3 0-.1l1-.2z\"/> </g> <use xlink:href=\"#nz-a\" transform=\"scale(-1 1)\"/> <use xlink:href=\"#nz-a\" transform=\"rotate(72 0 0)\"/> <use xlink:href=\"#nz-a\" transform=\"rotate(-72 0 0)\"/> <use xlink:href=\"#nz-a\" transform=\"scale(-1 1)rotate(72)\"/> </g> </defs> <path fill=\"#00247d\" fill-rule=\"evenodd\" d=\"M0 0h640v480H0z\"/> <g transform=\"translate(-111 36.1)scale(.66825)\"> <use xlink:href=\"#nz-b\" width=\"100%\" height=\"100%\" fill=\"#fff\" transform=\"translate(900 120)scale(45.4)\"/> <use xlink:href=\"#nz-b\" width=\"100%\" height=\"100%\" fill=\"#cc142b\" transform=\"matrix(30 0 0 30 900 120)\"/> </g> <g transform=\"rotate(82 525.2 114.6)scale(.66825)\"> <use xlink:href=\"#nz-b\" width=\"100%\" height=\"100%\" fill=\"#fff\" transform=\"rotate(-82 519 -457.7)scale(40.4)\"/> <use xlink:href=\"#nz-b\" width=\"100%\" height=\"100%\" fill=\"#cc142b\" transform=\"rotate(-82 519 -457.7)scale(25)\"/> </g> <g transform=\"rotate(82 525.2 114.6)scale(.66825)\"> <use xlink:href=\"#nz-b\" width=\"100%\" height=\"100%\" fill=\"#fff\" transform=\"rotate(-82 668.6 -327.7)scale(45.4)\"/> <use xlink:href=\"#nz-b\" width=\"100%\" height=\"100%\" fill=\"#cc142b\" transform=\"rotate(-82 668.6 -327.7)scale(30)\"/> </g> <g transform=\"translate(-111 36.1)scale(.66825)\"> <use xlink:href=\"#nz-b\" width=\"100%\" height=\"100%\" fill=\"#fff\" transform=\"translate(900 480)scale(50.4)\"/> <use xlink:href=\"#nz-b\" width=\"100%\" height=\"100%\" fill=\"#cc142b\" transform=\"matrix(35 0 0 35 900 480)\"/> </g> <path fill=\"#012169\" d=\"M0 0h320v240H0z\"/> <path fill=\"#fff\" d=\"m37.5 0 122 90.5L281 0h39v31l-120 89.5 120 89V240h-40l-120-89.5L40.5 240H0v-30l119.5-89L0 32V0z\"/> <path fill=\"#c8102e\" d=\"M212 140.5 320 220v20l-135.5-99.5zm-92 10 3 17.5-96 72H0zM320 0v1.5l-124.5 94 1-22L295 0zM0 0l119.5 88h-30L0 21z\"/> <path fill=\"#fff\" d=\"M120.5 0v240h80V0zM0 80v80h320V80z\"/> <path fill=\"#c8102e\" d=\"M0 96.5v48h320v-48zM136.5 0v240h48V0z\"/> </svg>","events":[{"year":1280,"date":"c. 1250–1300","era":"maori","tag":"Māori foundations","title":"Polynesian settlement","summary":"The ancestors of Māori settle Aotearoa.","what":"Polynesian navigators established communities that developed distinct iwi, hapū, language and tikanga.","why":"Māori sovereignty and biculturalism are foundational, not later additions to New Zealand history.","keywords":["Māori","Aotearoa","tikanga"],"colle":"What does it mean to recognise Indigenous sovereignty in a modern state?"},{"year":1642,"date":"1642","era":"colonial","tag":"Encounter & colonisation","title":"Abel Tasman reaches New Zealand","summary":"The first recorded European encounter is violent.","what":"Tasman’s expedition sighted the islands and clashed with Māori in Golden Bay.","why":"The encounter began European mapping without establishing control.","keywords":["Abel Tasman","European encounter","Golden Bay"],"colle":"Why do “discovery” narratives erase Indigenous knowledge?"},{"year":1769,"date":"1769","era":"colonial","tag":"Encounter & colonisation","title":"Cook maps the islands","summary":"British knowledge and imperial interest expand.","what":"James Cook circumnavigated and mapped New Zealand while engaging in both exchange and conflict with Māori.","why":"His voyages prepared later trade, missionary activity and colonisation.","keywords":["James Cook","mapping","British Empire"],"colle":"Can exploration ever be politically neutral?"},{"year":1840,"date":"1840","era":"colonial","tag":"Encounter & colonisation","title":"The Treaty of Waitangi","summary":"The foundational agreement is signed in English and Māori.","what":"Many rangatira signed versions that differed over whether sovereignty or governance was ceded.","why":"Conflicting texts and repeated breaches remain central to law, politics and national identity.","keywords":["Treaty of Waitangi","rangatiratanga","Crown"],"colle":"Can a state be legitimate when its founding treaty is disputed?"},{"year":1845,"date":"1845–72","era":"colonial","tag":"Encounter & colonisation","title":"The New Zealand Wars","summary":"Conflict accompanies land acquisition and Crown expansion.","what":"British and colonial forces fought Māori movements resisting loss of land and authority.","why":"Confiscations created grievances that later Treaty settlements sought to address.","keywords":["New Zealand Wars","land confiscation","Māori resistance"],"colle":"How should a country commemorate wars once excluded from national memory?"},{"year":1867,"date":"1867","era":"colonial","tag":"Encounter & colonisation","title":"Māori parliamentary seats","summary":"Reserved representation is created.","what":"Four Māori electorates were established, initially as a temporary measure.","why":"The seats provided representation but also reflected unequal assumptions about property and citizenship.","keywords":["Māori electorates","representation","Parliament"],"colle":"Do reserved seats strengthen equality or institutionalise difference?"},{"year":1893,"date":"1893","era":"reform","tag":"Democracy & reform","title":"Women’s suffrage","summary":"New Zealand becomes the first self-governing country where women vote nationally.","what":"A mass campaign led by figures including Kate Sheppard secured the vote for women.","why":"The achievement became a durable symbol of progressive national identity.","keywords":["women’s suffrage","Kate Sheppard","democracy"],"colle":"Why did New Zealand lead the world on women’s suffrage?"},{"year":1907,"date":"1907","era":"nation","tag":"Nation & independence","title":"Dominion status","summary":"New Zealand becomes a dominion within the British Empire.","what":"The constitutional label changed while strong political and cultural ties to Britain remained.","why":"It illustrates the gradual rather than revolutionary path to independence.","keywords":["Dominion","British Empire","constitutional evolution"],"colle":"When does a colony truly become independent?"},{"year":1915,"date":"1915","era":"nation","tag":"Nation & independence","title":"Gallipoli and ANZAC","summary":"Shared sacrifice with Australia becomes a national myth.","what":"New Zealand troops suffered heavy casualties in the failed Gallipoli campaign.","why":"ANZAC memory strengthened national consciousness while remaining intertwined with Empire.","keywords":["ANZAC","Gallipoli","national memory"],"colle":"Does wartime sacrifice provide a healthy basis for national identity?"},{"year":1947,"date":"1947","era":"nation","tag":"Nation & independence","title":"Full legislative independence","summary":"Parliament adopts the Statute of Westminster.","what":"New Zealand accepted full legislative autonomy from Britain.","why":"The late adoption reflected enduring attachment to Britain and the absence of a dramatic independence struggle.","keywords":["Statute of Westminster","independence","Britain"],"colle":"Why was New Zealand slow to formalise independence?"},{"year":1975,"date":"1975","era":"bicultural","tag":"Bicultural revival","title":"The Waitangi Tribunal and Land March","summary":"Māori protest forces historical grievances onto the national agenda.","what":"The Tribunal was created to examine Treaty claims, while the Land March opposed further alienation of Māori land.","why":"The year marked a turning point in the Māori renaissance and the politics of redress.","keywords":["Waitangi Tribunal","Land March","Māori renaissance"],"colle":"Can legal settlements repair cultural and territorial dispossession?"},{"year":1984,"date":"1984–90","era":"bicultural","tag":"Bicultural revival","title":"Rogernomics","summary":"Rapid market reform transforms the economy.","what":"The Labour government deregulated finance, cut subsidies and privatised state assets.","why":"The reforms increased efficiency in some sectors but also unemployment, inequality and debate over neoliberalism.","keywords":["Rogernomics","deregulation","inequality"],"colle":"Did market reform modernise New Zealand at too high a social cost?"},{"year":1985,"date":"1985–87","era":"bicultural","tag":"Bicultural revival","title":"Rainbow Warrior and the nuclear-free policy","summary":"New Zealand asserts an independent foreign policy.","what":"French agents sank the Greenpeace ship Rainbow Warrior, while nuclear-free legislation restricted visits by nuclear-capable vessels.","why":"The dispute with France and the United States made anti-nuclear policy a badge of national independence.","keywords":["Rainbow Warrior","nuclear-free","foreign policy"],"colle":"Can a small country influence global security norms?"},{"year":1987,"date":"1987","era":"bicultural","tag":"Bicultural revival","title":"Te reo Māori becomes an official language","summary":"The state recognises the Māori language.","what":"The Māori Language Act granted official status and created institutions to support revitalisation.","why":"Language revival became central to biculturalism and decolonisation.","keywords":["te reo Māori","language revival","biculturalism"],"colle":"Can official status reverse language decline?"},{"year":1993,"date":"1993–96","era":"bicultural","tag":"Bicultural revival","title":"MMP electoral reform","summary":"Voters replace first-past-the-post with proportional representation.","what":"A referendum adopted Mixed Member Proportional representation, first used in 1996.","why":"MMP diversified Parliament and made coalition government normal.","keywords":["MMP","proportional representation","coalitions"],"colle":"Does proportional representation improve democratic legitimacy?"},{"year":2011,"date":"2011","era":"contemporary","tag":"Contemporary New Zealand","title":"The Christchurch earthquake","summary":"A major disaster reshapes the country’s second-largest city.","what":"The earthquake killed 185 people and caused extensive destruction.","why":"Recovery raised questions about resilience, insurance, urban planning and centralised decision-making.","keywords":["Christchurch earthquake","resilience","reconstruction"],"colle":"How should governments balance speed and participation after disaster?"},{"year":2017,"date":"2017","era":"contemporary","tag":"Contemporary New Zealand","title":"Jacinda Ardern becomes Prime Minister","summary":"A new style of progressive leadership gains global attention.","what":"Ardern formed a coalition government and emphasised empathy, child poverty reduction and wellbeing.","why":"Her leadership became a global symbol while domestic debates continued over housing, inequality and delivery.","keywords":["Jacinda Ardern","wellbeing budget","progressive leadership"],"colle":"Does political empathy translate into effective government?"},{"year":2019,"date":"2019","era":"contemporary","tag":"Contemporary New Zealand","title":"The Christchurch mosque attacks","summary":"White-supremacist terrorism kills 51 worshippers.","what":"A gunman attacked two mosques; the government rapidly tightened firearms laws and promoted social solidarity.","why":"The response was praised internationally but also exposed Islamophobia and online extremism.","keywords":["Christchurch attacks","gun reform","extremism"],"colle":"Can decisive gun reform prevent future violence?"},{"year":2020,"date":"2020","era":"contemporary","tag":"Contemporary New Zealand","title":"The COVID-19 response","summary":"An elimination strategy wins global attention.","what":"Strict border controls, lockdowns and public-health communication initially kept deaths low.","why":"The strategy reinforced the image of competent small-state government but later produced fatigue and polarisation.","keywords":["COVID-19","elimination strategy","public trust"],"colle":"Why did pandemic consensus eventually weaken?"},{"year":2023,"date":"2023","era":"contemporary","tag":"Contemporary New Zealand","title":"National returns to power","summary":"Christopher Luxon forms a three-party coalition.","what":"National governed with ACT and New Zealand First after Labour’s support fell sharply.","why":"The change brought a more conservative programme and renewed conflict over Māori policy, public spending and the Treaty.","keywords":["Christopher Luxon","coalition government","2023 election"],"colle":"Is New Zealand entering a more polarised political era?"},{"year":2024,"date":"2024–25","era":"contemporary","tag":"Contemporary New Zealand","title":"The Treaty Principles Bill debate","summary":"A proposed rewrite of Treaty principles triggers mass opposition and is defeated.","what":"ACT’s bill passed a first reading amid a major hīkoi but was rejected at its second reading in April 2025.","why":"The controversy revealed deep disagreement over equality, partnership, Māori rights and the meaning of the Treaty.","keywords":["Treaty Principles Bill","hīkoi","Māori rights"],"colle":"Can one legal definition settle the meaning of the Treaty of Waitangi?"}],"priority":["c. 1250–1300 — Māori settlement","1840 — the Treaty of Waitangi","1845–72 — the New Zealand Wars","1893 — women’s suffrage","1947 — legislative independence","1975 — Tribunal and Land March","1985–87 — nuclear-free policy and te reo Māori","1993–96 — MMP","2019 — the Christchurch attacks","2020 — the COVID response","2023–25 — coalition government and Treaty debate"]},"in":{"name":"India","strap":"From Company rule and anti-colonial nationalism to a vast democratic republic, economic transformation and Modi’s third term.","flag":"<svg xmlns=\"http://www.w3.org/2000/svg\" xmlns:xlink=\"http://www.w3.org/1999/xlink\" id=\"flag-icons-in\" viewBox=\"0 0 640 480\"> <path fill=\"#f93\" d=\"M0 0h640v160H0z\"/> <path fill=\"#fff\" d=\"M0 160h640v160H0z\"/> <path fill=\"#128807\" d=\"M0 320h640v160H0z\"/> <g transform=\"matrix(3.2 0 0 3.2 320 240)\"> <circle r=\"20\" fill=\"#008\"/> <circle r=\"17.5\" fill=\"#fff\"/> <circle r=\"3.5\" fill=\"#008\"/> <g id=\"in-d\"> <g id=\"in-c\"> <g id=\"in-b\"> <g id=\"in-a\" fill=\"#008\"> <circle r=\".9\" transform=\"rotate(7.5 -8.8 133.5)\"/> <path d=\"M0 17.5.6 7 0 2l-.6 5z\"/> </g> <use xlink:href=\"#in-a\" width=\"100%\" height=\"100%\" transform=\"rotate(15)\"/> </g> <use xlink:href=\"#in-b\" width=\"100%\" height=\"100%\" transform=\"rotate(30)\"/> </g> <use xlink:href=\"#in-c\" width=\"100%\" height=\"100%\" transform=\"rotate(60)\"/> </g> <use xlink:href=\"#in-d\" width=\"100%\" height=\"100%\" transform=\"rotate(120)\"/> <use xlink:href=\"#in-d\" width=\"100%\" height=\"100%\" transform=\"rotate(-120)\"/> </g> </svg>","events":[{"year":1757,"date":"1757","era":"company","tag":"Company rule & the Raj","title":"The Battle of Plassey","summary":"The East India Company becomes a territorial power.","what":"Company forces defeated the Nawab of Bengal and gained decisive influence over a wealthy province.","why":"Commercial power turned into colonial rule, making private corporate violence central to the origins of the Raj.","keywords":["East India Company","Plassey","colonial rule"],"colle":"Can a private company become an empire?"},{"year":1857,"date":"1857–58","era":"company","tag":"Company rule & the Raj","title":"The Rebellion of 1857","summary":"A vast uprising ends Company rule.","what":"Indian soldiers and civilians rebelled across northern and central India in a conflict remembered variously as a mutiny or a war of independence.","why":"Britain transferred power to the Crown and reorganised the Raj.","keywords":["1857 Rebellion","Sepoy Mutiny","British Raj"],"colle":"How does the name given to a rebellion shape historical memory?"},{"year":1885,"date":"1885","era":"nationalism","tag":"Nationalism & independence","title":"The Indian National Congress is founded","summary":"An all-India political organisation emerges.","what":"Educated Indian leaders created a forum that initially sought reform within the Empire.","why":"Congress later became the principal movement for mass anti-colonial nationalism.","keywords":["Indian National Congress","nationalism","self-government"],"colle":"How do moderate reform movements become revolutionary?"},{"year":1905,"date":"1905","era":"nationalism","tag":"Nationalism & independence","title":"Partition of Bengal and Swadeshi","summary":"British administrative division provokes mass resistance.","what":"The partition of Bengal was opposed through boycotts, indigenous production and political mobilisation.","why":"The Swadeshi movement broadened nationalism but also sharpened communal and regional tensions.","keywords":["Partition of Bengal","Swadeshi","boycott"],"colle":"Can economic nationalism unite a diverse society?"},{"year":1919,"date":"1919","era":"nationalism","tag":"Nationalism & independence","title":"The Amritsar massacre","summary":"British troops kill unarmed civilians at Jallianwala Bagh.","what":"General Dyer ordered fire on a trapped crowd, causing hundreds of deaths.","why":"The massacre destroyed faith in gradual imperial reform for many Indians.","keywords":["Amritsar massacre","Jallianwala Bagh","colonial violence"],"colle":"Can an empire retain legitimacy after state violence?"},{"year":1930,"date":"1930","era":"nationalism","tag":"Nationalism & independence","title":"The Salt March","summary":"Gandhi turns salt into a symbol of civil disobedience.","what":"Marchers defied the colonial salt monopoly through a carefully staged non-violent campaign.","why":"The action demonstrated the political power of mass participation, symbolism and media attention.","keywords":["Mahatma Gandhi","Salt March","civil disobedience"],"colle":"Is non-violent resistance more effective than armed struggle?"},{"year":1942,"date":"1942","era":"nationalism","tag":"Nationalism & independence","title":"The Quit India Movement","summary":"Congress demands immediate British withdrawal.","what":"Leaders were arrested as protests and repression spread during the Second World War.","why":"Although suppressed, the movement showed that post-war imperial rule would be unsustainable.","keywords":["Quit India","Congress","decolonisation"],"colle":"Did the Second World War make Indian independence inevitable?"},{"year":1947,"date":"1947","era":"republic","tag":"Independence & republic","title":"Independence and Partition","summary":"Freedom arrives with mass displacement and killing.","what":"British India was divided into India and Pakistan, prompting one of history’s largest forced migrations.","why":"Partition remains central to relations with Pakistan, minority politics and the Kashmir dispute.","keywords":["Partition","independence","communal violence"],"colle":"Was Partition the unavoidable price of independence?"},{"year":1950,"date":"1950","era":"republic","tag":"Independence & republic","title":"The Constitution","summary":"India becomes a sovereign democratic republic.","what":"The constitution established universal adult suffrage, federalism, fundamental rights and a secular state.","why":"It created democratic institutions on an extraordinary scale in a poor, diverse and recently partitioned country.","keywords":["Constitution","secularism","universal suffrage"],"colle":"How has India sustained democracy despite immense diversity?"},{"year":1951,"date":"1951–52","era":"republic","tag":"Independence & republic","title":"The first general election","summary":"Hundreds of millions participate in universal suffrage.","what":"India organised a vast multi-phase election despite poverty, illiteracy and limited infrastructure.","why":"The success gave democratic legitimacy to the republic and normalised electoral competition.","keywords":["first general election","Election Commission","mass democracy"],"colle":"Why did democracy take root in India?"},{"year":1971,"date":"1971","era":"republic","tag":"Independence & republic","title":"War and the creation of Bangladesh","summary":"India defeats Pakistan in a decisive regional war.","what":"India intervened after mass displacement and conflict in East Pakistan, which became Bangladesh.","why":"The victory confirmed India’s regional power but deepened rivalry with Pakistan.","keywords":["Bangladesh","India-Pakistan war","regional power"],"colle":"Can humanitarian intervention be separated from strategic interest?"},{"year":1975,"date":"1975–77","era":"republic","tag":"Independence & republic","title":"The Emergency","summary":"Democratic freedoms are suspended.","what":"Indira Gandhi’s government ruled by decree, censored the press and detained opponents.","why":"Voters later removed her from office, making the period both a warning about authoritarianism and evidence of democratic resilience.","keywords":["the Emergency","Indira Gandhi","civil liberties"],"colle":"Could India’s democracy survive another Emergency?"},{"year":1984,"date":"1984","era":"transformation","tag":"Conflict & transformation","title":"Operation Blue Star and Indira Gandhi’s assassination","summary":"Conflict in Punjab produces national trauma.","what":"The army entered the Golden Temple to remove militants; Sikh bodyguards later assassinated the Prime Minister, followed by anti-Sikh massacres.","why":"The year exposed the dangers of religious conflict, state force and impunity.","keywords":["Operation Blue Star","anti-Sikh violence","Punjab"],"colle":"How should democracies respond to separatist violence without targeting communities?"},{"year":1991,"date":"1991","era":"transformation","tag":"Conflict & transformation","title":"Economic liberalisation","summary":"India turns away from a heavily regulated economy.","what":"A balance-of-payments crisis prompted deregulation, lower trade barriers and greater foreign investment.","why":"Reform accelerated growth and created a large middle class while widening regional and social inequalities.","keywords":["liberalisation","economic growth","inequality"],"colle":"Has liberalisation benefited India fairly?"},{"year":1992,"date":"1992","era":"transformation","tag":"Conflict & transformation","title":"The demolition of the Babri Masjid","summary":"Hindu nationalist mobilisation reaches a turning point.","what":"A Hindu nationalist crowd destroyed the mosque at Ayodhya, triggering communal violence.","why":"The event accelerated the rise of the BJP and made religion even more central to national politics.","keywords":["Babri Masjid","Hindutva","communalism"],"colle":"Can India remain both Hindu-majority and secular?"},{"year":1998,"date":"1998","era":"transformation","tag":"Conflict & transformation","title":"Nuclear tests","summary":"India openly declares itself a nuclear-armed power.","what":"The government conducted tests at Pokhran, followed by Pakistani tests.","why":"Nuclear weapons enhanced status and deterrence while increasing regional risk.","keywords":["Pokhran","nuclear weapons","Pakistan"],"colle":"Do nuclear weapons make South Asia safer?"},{"year":2005,"date":"2005","era":"transformation","tag":"Conflict & transformation","title":"The Right to Information Act","summary":"Citizens gain a powerful anti-corruption tool.","what":"The law allowed people to request records from public authorities.","why":"It strengthened transparency and grassroots accountability, although later implementation and institutional independence became contested.","keywords":["Right to Information","transparency","corruption"],"colle":"Can transparency laws overcome entrenched corruption?"},{"year":2008,"date":"2008","era":"transformation","tag":"Conflict & transformation","title":"The Mumbai attacks","summary":"Coordinated terrorism strikes India’s financial capital.","what":"Ten attackers targeted hotels, a railway station and other sites, killing more than 160 people.","why":"The attacks reshaped security policy and intensified India-Pakistan tensions.","keywords":["Mumbai attacks","terrorism","security"],"colle":"How should democracies respond to cross-border terrorism?"},{"year":2014,"date":"2014","era":"modi","tag":"The Modi era","title":"Narendra Modi comes to power","summary":"The BJP wins a parliamentary majority.","what":"Modi campaigned on development, strong leadership and Hindu nationalist themes.","why":"The election began a dominant political era that reshaped federalism, media, welfare and the meaning of secularism.","keywords":["Narendra Modi","BJP","Hindutva"],"colle":"Has Modi strengthened India or weakened its pluralism?"},{"year":2016,"date":"2016","era":"modi","tag":"The Modi era","title":"Demonetisation","summary":"Most high-value banknotes are suddenly withdrawn.","what":"The government presented the measure as an attack on undeclared wealth and counterfeit currency.","why":"The disruption accelerated digital payments but its economic benefits remain heavily disputed.","keywords":["demonetisation","cash economy","digital payments"],"colle":"Was demonetisation bold reform or avoidable disruption?"},{"year":2017,"date":"2017","era":"modi","tag":"The Modi era","title":"The Goods and Services Tax","summary":"A national indirect tax seeks to create one market.","what":"GST replaced many state and federal taxes with a unified system.","why":"The reform strengthened economic integration but created complexity for small businesses and federal tensions.","keywords":["GST","single market","federalism"],"colle":"Can economic centralisation coexist with Indian federalism?"},{"year":2019,"date":"2019","era":"modi","tag":"The Modi era","title":"Article 370 is abrogated","summary":"Jammu and Kashmir loses its special constitutional status.","what":"The government divided the former state into two union territories and imposed sweeping security restrictions.","why":"Supporters called it integration; critics saw an attack on federalism, rights and Kashmiri consent.","keywords":["Article 370","Kashmir","federalism"],"colle":"Can national integration be imposed without local consent?"},{"year":2020,"date":"2020–21","era":"modi","tag":"The Modi era","title":"Farm laws and mass protest","summary":"Farmers force the repeal of major market reforms.","what":"Three agricultural laws prompted a year-long protest movement around Delhi.","why":"Their withdrawal showed that mass mobilisation can still constrain a strong majority government.","keywords":["farmers’ protests","agriculture","protest"],"colle":"How powerful is civil society under a dominant government?"},{"year":2023,"date":"2023","era":"modi","tag":"The Modi era","title":"Population, G20 and the Moon","summary":"India’s global profile rises sharply.","what":"India became the world’s most populous country, hosted the G20 summit and landed Chandrayaan-3 near the Moon’s south pole.","why":"The achievements reinforced claims that India is an emerging technological and diplomatic power.","keywords":["G20","Chandrayaan-3","demographic power"],"colle":"Can India convert global prestige into broad domestic development?"},{"year":2024,"date":"2024","era":"modi","tag":"The Modi era","title":"Modi wins a third term without a BJP majority","summary":"Coalition politics returns at the national level.","what":"The BJP remained the largest party but lost its single-party majority; the NDA coalition kept Narendra Modi in office.","why":"The result checked BJP dominance while confirming Modi’s continuing centrality.","keywords":["2024 election","NDA coalition","third term"],"colle":"Did the 2024 election strengthen Indian democracy?"}],"priority":["1757 — Plassey and Company rule","1857 — the Rebellion","1885 — Congress is founded","1919 — Amritsar","1930 — the Salt March","1947 — Independence and Partition","1950–52 — Constitution and first election","1975–77 — the Emergency","1991 — liberalisation","1992 — Babri Masjid","2014 — Modi comes to power","2019 — Article 370","2024 — Modi’s third term"]},"za":{"name":"South Africa","strap":"From African kingdoms and settler conquest to apartheid, democratic transition and the 2024 Government of National Unity.","flag":"<svg xmlns=\"http://www.w3.org/2000/svg\" id=\"flag-icons-za\" viewBox=\"0 0 640 480\"> <defs> <clipPath id=\"za-a\"> <path fill-opacity=\".7\" d=\"M-71.9 0h682.7v512H-71.9z\"/> </clipPath> </defs> <g clip-path=\"url(#za-a)\" transform=\"translate(67.4)scale(.93748)\"> <g fill-rule=\"evenodd\" stroke-width=\"1pt\"> <path fill=\"#000001\" d=\"M-71.9 407.8V104.4L154 256.1z\"/> <path fill=\"#000c8a\" d=\"m82.2 512.1 253.6-170.6H696V512H82.2z\"/> <path fill=\"#e1392d\" d=\"M66 0h630v170.8H335.7S69.3-1.7 66 0\"/> <path fill=\"#ffb915\" d=\"M-71.9 64v40.4L154 256-72 407.8v40.3l284.5-192z\"/> <path fill=\"#007847\" d=\"M-71.9 64V0h95l301.2 204h371.8v104.2H324.3L23 512h-94.9v-63.9l284.4-192L-71.8 64z\"/> <path fill=\"#fff\" d=\"M23 0h59.2l253.6 170.7H696V204H324.3zm0 512.1h59.2l253.6-170.6H696v-33.2H324.3L23 512z\"/> </g> </g> </svg>","events":[{"year":1000,"date":"c. 1000–1300","era":"precolonial","tag":"African societies & colonisation","title":"Mapungubwe flourishes","summary":"A sophisticated southern African kingdom controls regional trade.","what":"Mapungubwe developed elite political authority and traded gold and ivory across the Indian Ocean world.","why":"It challenges colonial narratives that present complex state formation as a European import.","keywords":["Mapungubwe","African kingdoms","Indian Ocean trade"],"colle":"Why are precolonial African states often absent from national narratives?"},{"year":1652,"date":"1652","era":"colonial","tag":"African societies & colonisation","title":"Dutch settlement at the Cape","summary":"A permanent settler colony is established.","what":"The Dutch East India Company created a refreshment station that expanded through land seizure, forced labour and slavery.","why":"The settlement laid foundations for Afrikaner identity and racial hierarchy.","keywords":["Cape Colony","Dutch East India Company","settler colonialism"],"colle":"How did labour and land shape racial categories?"},{"year":1835,"date":"1830s–40s","era":"colonial","tag":"African societies & colonisation","title":"The Great Trek","summary":"Boer settlers move inland beyond British rule.","what":"Thousands of Voortrekkers established republics after conflicts with African kingdoms and communities.","why":"The Trek became a powerful Afrikaner nationalist myth of independence and divine mission.","keywords":["Great Trek","Voortrekkers","Afrikaner nationalism"],"colle":"How do migration stories become nationalist myths?"},{"year":1867,"date":"1867–86","era":"colonial","tag":"African societies & colonisation","title":"Diamonds and gold","summary":"Mineral discoveries transform the region.","what":"Diamonds at Kimberley and gold on the Witwatersrand produced rapid industrialisation and migrant labour.","why":"The mineral economy intensified imperial rivalry, urbanisation and racial labour control.","keywords":["diamonds","gold","migrant labour"],"colle":"Did mining create modern South Africa or entrench inequality?"},{"year":1899,"date":"1899–1902","era":"colonial","tag":"African societies & colonisation","title":"The South African War","summary":"Britain defeats the Boer republics.","what":"The war included guerrilla fighting and British concentration camps for Boer and Black civilians.","why":"Its settlement reconciled white elites while largely excluding the Black majority.","keywords":["South African War","concentration camps","British Empire"],"colle":"Can reconciliation between former enemies be unjust to excluded groups?"},{"year":1910,"date":"1910","era":"segregation","tag":"Union & segregation","title":"The Union of South Africa","summary":"A self-governing dominion unites four colonies.","what":"Political power was consolidated in a white-controlled state within the British Empire.","why":"Union created national institutions while excluding most Black South Africans from citizenship and power.","keywords":["Union of South Africa","white minority rule","Dominion"],"colle":"Was the modern state founded on racial exclusion?"},{"year":1912,"date":"1912","era":"segregation","tag":"Union & segregation","title":"The ANC is founded","summary":"A national organisation begins the struggle for African political rights.","what":"The South African Native National Congress, later the ANC, sought to resist dispossession and exclusion.","why":"It became the leading liberation movement and later the dominant governing party.","keywords":["ANC","liberation movement","African nationalism"],"colle":"Can a liberation movement successfully become a governing party?"},{"year":1913,"date":"1913","era":"segregation","tag":"Union & segregation","title":"The Natives Land Act","summary":"Black land ownership is severely restricted.","what":"The law confined most African land rights to small designated reserves.","why":"It entrenched dispossession, rural poverty and the migrant-labour system long before formal apartheid.","keywords":["Natives Land Act","land dispossession","segregation"],"colle":"Should land reform prioritise restitution, redistribution or productivity?"},{"year":1948,"date":"1948","era":"apartheid","tag":"Apartheid","title":"Apartheid begins","summary":"The National Party formalises racial separation.","what":"A network of laws classified people by race and controlled residence, work, education, movement and political rights.","why":"Apartheid converted existing segregation into a comprehensive authoritarian system.","keywords":["apartheid","racial classification","National Party"],"colle":"How did law make racial domination appear normal?"},{"year":1955,"date":"1955","era":"apartheid","tag":"Apartheid","title":"The Freedom Charter","summary":"The anti-apartheid movement sets out a democratic alternative.","what":"The Congress of the People declared that South Africa belongs to all who live in it.","why":"Its principles influenced the later democratic constitution and continue to shape arguments about social and economic justice.","keywords":["Freedom Charter","Congress of the People","non-racialism"],"colle":"Has post-apartheid South Africa fulfilled the Freedom Charter?"},{"year":1960,"date":"1960","era":"apartheid","tag":"Apartheid","title":"The Sharpeville massacre","summary":"Police kill protesters opposing pass laws.","what":"Sixty-nine people were killed, many shot in the back, during a peaceful demonstration.","why":"The massacre prompted international outrage, the banning of liberation movements and a turn towards armed struggle.","keywords":["Sharpeville","pass laws","state violence"],"colle":"When does repression make armed resistance inevitable?"},{"year":1964,"date":"1964","era":"apartheid","tag":"Apartheid","title":"The Rivonia Trial","summary":"Nelson Mandela and other leaders receive life sentences.","what":"The defendants used the trial to condemn apartheid and explain the turn to sabotage.","why":"Mandela’s imprisonment made him a global symbol of resistance.","keywords":["Rivonia Trial","Nelson Mandela","political prisoners"],"colle":"Can a political trial strengthen the cause it seeks to suppress?"},{"year":1976,"date":"1976","era":"apartheid","tag":"Apartheid","title":"The Soweto Uprising","summary":"Schoolchildren revolt against apartheid education.","what":"Police fired on students protesting compulsory Afrikaans instruction.","why":"The uprising radicalised a generation and destroyed the regime’s claim to stability.","keywords":["Soweto Uprising","Bantu Education","youth protest"],"colle":"Why are students often central to democratic movements?"},{"year":1990,"date":"1990","era":"transition","tag":"Transition to democracy","title":"Mandela is freed and the ANC unbanned","summary":"Negotiated transition begins.","what":"President F. W. de Klerk lifted bans on liberation movements and released Nelson Mandela.","why":"The decision opened a difficult process combining negotiation, violence and constitutional compromise.","keywords":["Mandela released","de Klerk","negotiations"],"colle":"Why did apartheid end through negotiation rather than revolution?"},{"year":1994,"date":"1994","era":"transition","tag":"Transition to democracy","title":"The first democratic election","summary":"Universal suffrage creates the “Rainbow Nation”.","what":"The ANC won the election and Nelson Mandela became president in a Government of National Unity.","why":"The peaceful transfer of power became a global symbol of democratic possibility.","keywords":["1994 election","Nelson Mandela","Rainbow Nation"],"colle":"Was the negotiated transition too generous to the old elite?"},{"year":1996,"date":"1996","era":"transition","tag":"Transition to democracy","title":"The Constitution and the TRC","summary":"A rights-based constitution and public reckoning shape the new democracy.","what":"The constitution entrenched equality and socio-economic rights, while the Truth and Reconciliation Commission heard testimony about apartheid crimes.","why":"South Africa became a model of constitutionalism and restorative justice, though material inequality endured.","keywords":["Constitution","Truth and Reconciliation Commission","restorative justice"],"colle":"Can truth and reconciliation substitute for punishment and redistribution?"},{"year":1999,"date":"1999","era":"democracy","tag":"Democratic South Africa","title":"The Mbeki presidency","summary":"The post-Mandela era prioritises African renewal and economic growth.","what":"Thabo Mbeki promoted the African Renaissance and market-oriented policy but his government’s HIV/AIDS denialism caused immense harm.","why":"The period illustrates the tension between technocratic ambition and democratic accountability.","keywords":["Thabo Mbeki","African Renaissance","HIV/AIDS"],"colle":"How should democracies respond when leaders reject scientific evidence?"},{"year":2010,"date":"2010","era":"democracy","tag":"Democratic South Africa","title":"The FIFA World Cup","summary":"South Africa hosts a global sporting event.","what":"The first World Cup held in Africa showcased infrastructure, culture and national pride.","why":"The event strengthened soft power but also raised questions about public spending and lasting benefits.","keywords":["FIFA World Cup","soft power","nation branding"],"colle":"Do mega-events produce lasting social benefits?"},{"year":2012,"date":"2012","era":"democracy","tag":"Democratic South Africa","title":"The Marikana massacre","summary":"Police kill striking mineworkers.","what":"Thirty-four workers were shot during a labour dispute at a platinum mine.","why":"Marikana exposed the persistence of economic inequality, labour conflict and state violence after apartheid.","keywords":["Marikana","mineworkers","police violence"],"colle":"Why has political freedom not ended economic exploitation?"},{"year":2015,"date":"2015–16","era":"democracy","tag":"Democratic South Africa","title":"Rhodes Must Fall and Fees Must Fall","summary":"Students demand decolonisation and affordable education.","what":"Campus movements challenged colonial symbols, curricula, fees and institutional racism.","why":"They placed unfinished transformation and generational frustration at the centre of national debate.","keywords":["Rhodes Must Fall","Fees Must Fall","decolonisation"],"colle":"What would a genuinely decolonised university look like?"},{"year":2018,"date":"2018","era":"democracy","tag":"Democratic South Africa","title":"Zuma resigns","summary":"A presidency defined by “state capture” ends.","what":"Jacob Zuma left office under pressure from the ANC after years of corruption allegations and institutional damage.","why":"The transition to Cyril Ramaphosa promised renewal but revealed the difficulty of reforming a dominant party from within.","keywords":["Jacob Zuma","state capture","Cyril Ramaphosa"],"colle":"Can a dominant party effectively police its own corruption?"},{"year":2021,"date":"2021","era":"democracy","tag":"Democratic South Africa","title":"July unrest","summary":"Violence and looting expose social fragility.","what":"Protests after Zuma’s imprisonment escalated into widespread unrest, particularly in KwaZulu-Natal and Gauteng.","why":"The crisis revealed inequality, unemployment, weak institutions and political factionalism.","keywords":["July unrest","unemployment","state capacity"],"colle":"How does extreme inequality threaten democracy?"},{"year":2024,"date":"2024","era":"democracy","tag":"Democratic South Africa","title":"The ANC loses its majority and a GNU is formed","summary":"One-party dominance ends after thirty years.","what":"The ANC won about 40% of the vote, Cyril Ramaphosa was re-elected by Parliament and a multi-party Government of National Unity was formed.","why":"The shift created an unprecedented test of coalition politics, accountability and policy compromise.","keywords":["2024 election","Government of National Unity","coalition politics"],"colle":"Can coalition government renew South African democracy?"}],"priority":["c. 1000–1300 — Mapungubwe","1652 — Dutch settlement","1867–86 — minerals and migrant labour","1910–13 — Union and the Land Act","1948 — apartheid","1960 — Sharpeville","1976 — Soweto","1990 — Mandela freed","1994 — democratic elections","1996 — Constitution and TRC","2012 — Marikana","2018 — Zuma resigns","2024 — ANC majority ends and GNU begins"]}};
